src/api/saveBook.ts.content:
import { z } from 'zod';
import { createEndpoint, Books, ZiteError } from 'zite-integrations-backend-sdk';

const bookInput = z.object({
  id: z.string().optional(),
  bookTitle: z.string(),
  bookType: z.string(),
  grade: z.string(),
  subject: z.string(),
  mapehSubject: z.string().optional(),
  authors: z.string().optional(),
  isbnNumber: z.string().optional(),
  publisher: z.string().optional(),
  copyrightYear: z.number().optional(),
  volume: z.string().optional(),
  schoolName: z.string(),
  district: z.string(),
  distributionDate: z.string(),
  totalUsable: z.number(),
  totalPartiallyDamaged: z.number(),
  totalDamaged: z.number(),
  totalLost: z.number(),
  totalCondemnable: z.number(),
  remarks: z.string().optional(),
});

export default createEndpoint({
  authenticated: true,
  description: 'Create or update a book. Enforces unique title per user. Auto-calculates total.',
  inputSchema: bookInput,
  outputSchema: z.object({ id: z.string() }),
  execute: async ({ input, context }) => {
    const existing = await Books.findAll({
      filters: { user: { contains: context.user.id }, bookTitle: input.bookTitle },
      limit: 5,
    });
    const duplicate = existing.records.find((r) => r.id !== input.id);
    if (duplicate) {
      throw new ZiteError({ code: 'CONFLICT', message: `A book titled "${input.bookTitle}" already exists.` });
    }

    const total = (input.totalUsable ?? 0) + (input.totalPartiallyDamaged ?? 0) +
      (input.totalDamaged ?? 0) + (input.totalLost ?? 0) + (input.totalCondemnable ?? 0);

    const fields = {
      bookTitle: input.bookTitle,
      bookType: input.bookType,
      grade: input.grade,
      subject: input.subject,
      mapehSubject: input.mapehSubject,
      authors: input.authors,
      isbnNumber: input.isbnNumber,
      publisher: input.publisher,
      copyrightYear: input.copyrightYear,
      volume: input.volume,
      schoolName: input.schoolName,
      district: input.district,
      distributionDate: input.distributionDate,
      totalUsable: input.totalUsable,
      totalPartiallyDamaged: input.totalPartiallyDamaged,
      totalDamaged: input.totalDamaged,
      totalLost: input.totalLost,
      totalCondemnable: input.totalCondemnable,
      total,
      remarks: input.remarks,
      user: context.user.id,
    };

    if (input.id) {
      const updated = await Books.update({ id: input.id, record: fields });
      return { id: updated.id };
    }
    const created = await Books.create({ record: fields });
    return { id: created.id };
  },
});

