import { useEffect, useState } from 'react';
import { getBooks } from 'zite-endpoints-sdk';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { BookOpen, BookMarked, AlertTriangle, Package } from 'lucide-react';
import { useAuth } from 'zite-auth-sdk';
import { SUBJECTS } from '@/lib/constants';

type Book = GetBooksOutputType['books'][0];

function StatCard({ title, value, icon: Icon, sub }: { title: string; value: string | number; icon: React.ElementType; sub?: string }) {
  return (
    <Card>
      <CardContent className="pt-5 flex items-start justify-between gap-3">
        <div>
          <p className="text-sm text-muted-foreground">{title}</p>
          <p className="text-3xl font-bold text-foreground mt-1">{typeof value === 'number' ? value.toLocaleString() : value}</p>
          {sub && <p className="text-xs text-muted-foreground mt-1">{sub}</p>}
        </div>
        <div className="bg-primary/10 rounded-lg p-2.5 shrink-0"><Icon className="h-5 w-5 text-primary" /></div>
      </CardContent>
    </Card>
  );
}

export default function DashboardPage() {
  const { user } = useAuth();
  const [books, setBooks] = useState<Book[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getBooks({}).then((r) => setBooks(r.books)).finally(() => setLoading(false));
  }, []);

  const totalBooks = books.length;
  const totalUsable = books.reduce((s, b) => s + (b.totalUsable ?? 0), 0);
  const grandTotal = books.reduce((s, b) => s + (b.total ?? 0), 0);
  const lowUsable = books.filter((b) => {
    const t = b.total ?? 0;
    return t > 0 && (b.totalUsable ?? 0) / t <= 0.25;
  });

  const bySubject = SUBJECTS.map((s) => ({
    name: s, count: books.filter((b) => b.subject === s).length,
  })).filter((s) => s.count > 0).sort((a, b) => b.count - a.count);

  const firstName = user?.firstName || user?.email?.split('@')[0] || 'there';

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-primary">Welcome back, {firstName}! 👋</h1>
        <p className="text-muted-foreground text-sm mt-1">Here's an overview of your learning resource inventory.</p>
      </div>

      {loading ? (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          {Array.from({ length: 4 }).map((_, i) => <Skeleton key={i} className="h-28 rounded-xl" />)}
        </div>
      ) : (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Total Books" value={totalBooks} icon={BookOpen} />
          <StatCard title="Total Usable" value={totalUsable} icon={BookMarked} />
          <StatCard title="Grand Total" value={grandTotal} icon={Package} />
          <StatCard title="Low Usable" value={lowUsable.length} icon={AlertTriangle}
            sub={lowUsable.length > 0 ? 'books need attention' : 'All good!'} />
        </div>
      )}

      {!loading && lowUsable.length > 0 && (
        <Card className="border-orange-200 bg-orange-50">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2 text-orange-700">
              <AlertTriangle className="h-4 w-4" /> Low Usable Copies ({lowUsable.length} books)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-1.5">
              {lowUsable.slice(0, 5).map((b) => (
                <div key={b.id} className="flex items-center justify-between text-sm">
                  <span className="font-medium text-foreground truncate max-w-[200px]">{b.bookTitle}</span>
                  <span className="text-orange-700 font-semibold shrink-0 ml-2">{b.totalUsable} usable of {b.total}</span>
                </div>
              ))}
              {lowUsable.length > 5 && <p className="text-xs text-orange-600 mt-1">+{lowUsable.length - 5} more</p>}
            </div>
          </CardContent>
        </Card>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card>
          <CardHeader><CardTitle className="text-base">Books by Subject</CardTitle></CardHeader>
          <CardContent>
            {loading ? <Skeleton className="h-40" /> : bySubject.length === 0 ? (
              <p className="text-muted-foreground text-sm text-center py-6">No data yet</p>
            ) : (
              <div className="space-y-3">
                {bySubject.map((s) => (
                  <div key={s.name}>
                    <div className="flex items-center justify-between text-sm mb-1">
                      <span className="text-foreground font-medium truncate max-w-[200px]">{s.name}</span>
                      <span className="text-muted-foreground shrink-0 ml-2">{s.count} book{s.count !== 1 ? 's' : ''}</span>
                    </div>
                    <div className="h-2 bg-muted rounded-full overflow-hidden">
                      <div className="h-full bg-primary rounded-full transition-all" style={{ width: `${(s.count / totalBooks) * 100}%` }} />
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>

        <Card>
          <CardHeader><CardTitle className="text-base">Recent Books (A–Z)</CardTitle></CardHeader>
          <CardContent>
            {loading ? <Skeleton className="h-40" /> : books.length === 0 ? (
              <p className="text-muted-foreground text-sm text-center py-6">No books added yet</p>
            ) : (
              <div className="space-y-3">
                {[...books].sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? '')).slice(0, 6).map((b) => (
                  <div key={b.id} className="flex items-start justify-between gap-2 text-sm border-b border-border pb-2 last:border-0 last:pb-0">
                    <div className="overflow-hidden">
                      <p className="font-medium text-foreground truncate">{b.bookTitle}</p>
                      <p className="text-xs text-muted-foreground">{b.grade} · {b.subject}</p>
                    </div>
                    <div className="text-right shrink-0">
                      <p className="font-semibold text-primary">{b.total?.toLocaleString()}</p>
                      <p className="text-xs text-muted-foreground">total</p>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

src/pages/InventoryPage.tsx.content:
import { useState, useEffect, useCallback } from 'react';
import { getBooks, saveBook, deleteBook } from 'zite-endpoints-sdk';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';
import BookTable from '@/components/BookTable';
import BookFormModal from '@/components/BookFormModal';
import { Toaster } from '@/components/ui/sonner';
import { toast } from 'sonner';

type Book = GetBooksOutputType['books'][0];

export default function InventoryPage() {
  const [books, setBooks] = useState<Book[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editBook, setEditBook] = useState<Book | null>(null);
  const [saving, setSaving] = useState(false);

  const fetchBooks = useCallback(async () => {
    setLoading(true);
    try { const result = await getBooks({}); setBooks(result.books); }
    catch { toast.error('Failed to load books'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchBooks(); }, [fetchBooks]);

  const handleSave = async (data: Omit<Book, 'id'> & { id?: string }) => {
    setSaving(true);
    try {
      await saveBook({
        bookTitle: data.bookTitle ?? '',
        bookType: data.bookType ?? '',
        grade: data.grade ?? '',
        subject: data.subject ?? '',
        mapehSubject: data.mapehSubject,
        authors: data.authors,
        isbnNumber: data.isbnNumber,
        publisher: data.publisher,
        copyrightYear: data.copyrightYear,
        volume: data.volume,
        schoolName: data.schoolName ?? '',
        district: data.district ?? '',
        distributionDate: data.distributionDate ?? '',
        totalUsable: data.totalUsable ?? 0,
        totalPartiallyDamaged: data.totalPartiallyDamaged ?? 0,
        totalDamaged: data.totalDamaged ?? 0,
        totalLost: data.totalLost ?? 0,
        totalCondemnable: data.totalCondemnable ?? 0,
        remarks: data.remarks,
        id: data.id,
      });
      toast.success(data.id ? 'Book updated!' : 'Book added!');
      setModalOpen(false);
      setEditBook(null);
      fetchBooks();
    } catch (e: any) {
      toast.error(e?.message ?? 'Failed to save book');
    } finally { setSaving(false); }
  };

  const handleDelete = async (id: string) => {
    await deleteBook({ id });
    toast.success('Book deleted');
    fetchBooks();
  };

  return (
    <div className="space-y-0">
      <Toaster />
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-foreground">Book Inventory</h1>
        <p className="text-muted-foreground text-sm mt-1">Manage your learning resource distribution records</p>
      </div>
      <BookTable
        books={books} loading={loading}
        onAdd={() => { setEditBook(null); setModalOpen(true); }}
        onEdit={(book) => { setEditBook(book); setModalOpen(true); }}
        onDelete={handleDelete} onRefresh={fetchBooks}
      />
      <BookFormModal
        open={modalOpen}
        onClose={() => { setModalOpen(false); setEditBook(null); }}
        onSave={handleSave} book={editBook} saving={saving}
      />
    </div>
  );
}

