function GoogleAvatar({
  email,
  firstName,
  lastName
}: {
  email?: string;
  firstName?: string;
  lastName?: string;
}) {
  const [imgError, setImgError] = useState(false);
  const fullName = [firstName, lastName].filter(Boolean).join('+') || email?.split('@')[0] || 'User';
  const initial = firstName ? firstName[0].toUpperCase() : email?.[0].toUpperCase() ?? '?';

  // Try Google's profile photo via their gstatic CDN (works for logged-in Google users)
  const googlePhotoUrl = email
    ? `https://lh3.googleusercontent.com/a/default-user=s40-c`
    : null;

  // Use ui-avatars as reliable personalized fallback with user's name
  const uiAvatarUrl = `https://ui-avatars.com/api/?name=${encodeURIComponent(fullName)}&size=64&bold=true&format=svg`;

  if (!imgError) {
    return (
      <img
        src={uiAvatarUrl}
        alt={initial}
        referrerPolicy="no-referrer"
        onError={() => setImgError(true)}
        className="h-8 w-8 rounded-full object-cover shrink-0 ring-2 ring-primary-foreground/30"
      />
    );
  }

  return (
    <div className="h-8 w-8 rounded-full bg-primary-foreground/20 ring-2 ring-primary-foreground/30 flex items-center justify-center text-xs font-bold shrink-0">
      {initial}
    </div>
  );
}
