import { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { SUBJECTS, DISTRICTS, DATE_RANGE_OPTIONS, GRADE_LEVELS } from '@/lib/constants';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];
interface Props { books: Book[] }

function getDateCutoff(range: string): Date | null {
  const now = new Date();
  if (range === '7days') return new Date(now.setDate(now.getDate() - 7));
  if (range === 'month') return new Date(now.setMonth(now.getMonth() - 1));
  if (range === 'quarter') return new Date(now.setMonth(now.getMonth() - 3));
  if (range === 'year') return new Date(now.setFullYear(now.getFullYear() - 1));
  return null;
}

export default function ReportsView({ books }: Props) {
  const [dateRange, setDateRange] = useState('all');
  const [district, setDistrict] = useState('all');
  const [subject, setSubject] = useState('all');
  const [gradeLevel, setGradeLevel] = useState('all');

  const filtered = useMemo(() => {
    const cutoff = getDateCutoff(dateRange);
    return books.filter((b) => {
      if (cutoff && b.distributionDate && new Date(b.distributionDate) < cutoff) return false;
      if (district !== 'all' && b.district !== district) return false;
      if (subject !== 'all' && b.subject !== subject) return false;
      if (gradeLevel !== 'all' && b.grade !== gradeLevel) return false;
      return true;
    });
  }, [books, dateRange, district, subject, gradeLevel]);

  const totalBooks = filtered.length;
  const totalUsable = filtered.reduce((s, b) => s + (b.totalUsable ?? 0), 0);
  const grandTotal = filtered.reduce((s, b) => s + (b.total ?? 0), 0);

  const bySubject = useMemo(() => SUBJECTS.map((s) => ({
    name: s.length > 14 ? s.slice(0, 14) + '…' : s, fullName: s,
    total: filtered.filter((b) => b.subject === s).reduce((a, b) => a + (b.total ?? 0), 0),
  })).filter((x) => x.total > 0), [filtered]);

  const byDistrict = useMemo(() => {
    const map: Record<string, number> = {};
    filtered.forEach((b) => { if (b.district) map[b.district] = (map[b.district] ?? 0) + (b.total ?? 0); });
    return Object.entries(map).map(([name, total]) => ({ name, total })).sort((a, b) => b.total - a.total).slice(0, 15);
  }, [filtered]);

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader><CardTitle className="text-base">Filters</CardTitle></CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <div><Label className="mb-1 block">Date Range</Label>
              <Select value={dateRange} onValueChange={setDateRange}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{DATE_RANGE_OPTIONS.map((o) => <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">Grade Level</Label>
              <Select value={gradeLevel} onValueChange={setGradeLevel}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent><SelectItem value="all">All Levels</SelectItem>{GRADE_LEVELS.map((g) => <SelectItem key={g} value={g}>{g}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">Subject</Label>
              <Select value={subject} onValueChange={setSubject}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent><SelectItem value="all">All Subjects</SelectItem>{SUBJECTS.map((s) => <SelectItem key={s} value={s}>{s}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">District</Label>
              <Select value={district} onValueChange={setDistrict}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent className="max-h-56"><SelectItem value="all">All Districts</SelectItem>{DISTRICTS.map((d) => <SelectItem key={d} value={d}>{d}</SelectItem>)}</SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
        <Card><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-primary">{totalBooks}</p><p className="text-sm text-muted-foreground mt-1">Total Books</p></CardContent></Card>
        <Card><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-green-700">{totalUsable.toLocaleString()}</p><p className="text-sm text-muted-foreground mt-1">Usable Copies</p></CardContent></Card>
        <Card className="col-span-2 sm:col-span-1"><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-primary">{grandTotal.toLocaleString()}</p><p className="text-sm text-muted-foreground mt-1">Grand Total</p></CardContent></Card>
      </div>

      {bySubject.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Books by Subject</CardTitle></CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={220}>
              <BarChart data={bySubject} margin={{ top: 5, right: 10, left: 0, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                <XAxis dataKey="name" tick={{ fontSize: 11 }} />
                <YAxis tick={{ fontSize: 11 }} />
                <Tooltip formatter={(v, _, p) => [v, p.payload.fullName]} />
                <Bar dataKey="total" className="fill-primary" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      )}

      {byDistrict.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Top Districts by Total Books</CardTitle></CardHeader>
          <CardContent>
            <div className="space-y-2">
              {byDistrict.map((d) => (
                <div key={d.name} className="flex items-center gap-3">
                  <span className="w-24 text-sm text-muted-foreground shrink-0">{d.name}</span>
                  <div className="flex-1 bg-muted rounded-full h-5 overflow-hidden">
                    <div className="bg-primary h-full rounded-full transition-all" style={{ width: `${(d.total / (byDistrict[0]?.total || 1)) * 100}%` }} />
                  </div>
                  <span className="text-sm font-semibold w-16 text-right">{d.total.toLocaleString()}</span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {filtered.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Distribution Details ({filtered.length} records)</CardTitle></CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-muted">
                  <tr>{['Title','Type','Grade','Subject','School','District','Date','Usable','Partial','Damaged','Lost','Condemnable','Total','Remarks'].map((h) => (
                    <th key={h} className="text-left px-3 py-2 font-semibold text-muted-foreground whitespace-nowrap text-xs">{h}</th>
                  ))}</tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {[...filtered].sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? '')).map((b) => (
                    <tr key={b.id} className="hover:bg-muted/40">
                      <td className="px-3 py-2 font-medium max-w-[130px] truncate">{b.bookTitle}</td>
                      <td className="px-3 py-2 max-w-[90px] truncate text-muted-foreground">{b.bookType}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.grade}</td>
                      <td className="px-3 py-2 max-w-[110px] truncate">{b.subject === 'MAPEH' && b.mapehSubject ? `MAPEH–${b.mapehSubject}` : b.subject}</td>
                      <td className="px-3 py-2 max-w-[110px] truncate text-muted-foreground">{b.schoolName}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.district}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.distributionDate ? new Date(b.distributionDate).toLocaleDateString() : '—'}</td>
                      <td className="px-3 py-2 text-right text-green-700 font-semibold">{b.totalUsable ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalPartiallyDamaged ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalDamaged ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalLost ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalCondemnable ?? 0}</td>
                      <td className="px-3 py-2 text-right font-bold text-primary">{b.total ?? 0}</td>
                      <td className="px-3 py-2 max-w-[100px] truncate text-muted-foreground text-xs">{b.remarks ?? '—'}</td>
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-muted font-semibold">
                  <tr>
                    <td colSpan={7} className="px-3 py-2 text-right text-sm">Totals:</td>
                    <td className="px-3 py-2 text-right text-green-700">{filtered.reduce((s, b) => s + (b.totalUsable ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalPartiallyDamaged ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalDamaged ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalLost ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalCondemnable ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right text-primary">{grandTotal.toLocaleString()}</td>
                    <td></td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </CardContent>
        </Card>
      )}
      {filtered.length === 0 && <div className="text-center py-12 text-muted-foreground"><p className="text-lg font-medium">No data for selected filters</p></div>}
    </div>
  );
}

