import { z } from 'zod';
import { createEndpoint, Books } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Get all books for the current user',
  inputSchema: z.object({}),
  outputSchema: z.object({
    books: z.array(z.object({
      id: z.string(),
      bookTitle: z.string().optional(),
      grade: z.string().optional(),
      subject: z.string().optional(),
      district: z.string().optional(),
      distributor: z.string().optional(),
      distributionDate: z.string().optional(),
      numberOfCopies: z.number().optional(),
    })),
  }),
  execute: async ({ context }) => {
    const result = await Books.findAll({
      filters: { user: { contains: context.user.id } },
      limit: 2000,
    });
    const books = result.records.map((b) => ({
      id: b.id,
      bookTitle: b.bookTitle,
      grade: b.grade,
      subject: b.subject,
      district: b.district,
      distributor: b.distributor,
      distributionDate: b.distributionDate,
      numberOfCopies: b.numberOfCopies,
    }));
    return { books };
  },
});

import { z } from 'zod';
import { createEndpoint, Books } from 'zite-integrations-backend-sdk';

const bookSchema = z.object({
  id: z.string().optional(),
  bookTitle: z.string(),
  grade: z.string(),
  subject: z.string(),
  district: z.string(),
  distributor: z.string(),
  distributionDate: z.string(),
  numberOfCopies: z.number(),
});

export default createEndpoint({
  authenticated: true,
  description: 'Create or update a book record',
  inputSchema: bookSchema,
  outputSchema: z.object({ id: z.string() }),
  execute: async ({ input, context }) => {
    const fields = {
      bookTitle: input.bookTitle,
      grade: input.grade,
      subject: input.subject,
      district: input.district,
      distributor: input.distributor,
      distributionDate: input.distributionDate,
      numberOfCopies: input.numberOfCopies,
      user: context.user.id,
    };

    if (input.id) {
      const updated = await Books.update({ id: input.id, record: fields });
      return { id: updated.id };
    } else {
      const created = await Books.create({ record: fields });
      return { id: created.id };
    }
  },
});

import { z } from 'zod';
import { createEndpoint, Books } from 'zite-integrations-backend-sdk';

export default createEndpoint({
  authenticated: true,
  description: 'Delete a book record',
  inputSchema: z.object({ id: z.string() }),
  outputSchema: z.object({ success: z.boolean() }),
  execute: async ({ input }) => {
    await Books.delete({ id: input.id });
    return { success: true };
  },
});

import { z } from 'zod';
import { createEndpoint, Books } from 'zite-integrations-backend-sdk';

const bookRow = z.object({
  bookTitle: z.string(),
  grade: z.string(),
  subject: z.string(),
  district: z.string(),
  distributor: z.string(),
  distributionDate: z.string(),
  numberOfCopies: z.number(),
});

export default createEndpoint({
  authenticated: true,
  description: 'Bulk import books from CSV data',
  inputSchema: z.object({ books: z.array(bookRow) }),
  outputSchema: z.object({ imported: z.number() }),
  execute: async ({ input, context }) => {
    const records = input.books.map((b) => ({
      bookTitle: b.bookTitle,
      grade: b.grade,
      subject: b.subject,
      district: b.district,
      distributor: b.distributor,
      distributionDate: b.distributionDate,
      numberOfCopies: b.numberOfCopies,
      user: context.user.id,
    }));

    // Split into chunks of 100
    for (let i = 0; i < records.length; i += 100) {
      await Books.bulkCreate({ records: records.slice(i, i + 100) });
    }
    return { imported: records.length };
  },
});

