import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { SUBJECTS, GRADES, DISTRICTS } from '@/lib/constants';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];

interface Props {
  open: boolean;
  onClose: () => void;
  onSave: (data: Omit<Book, 'id'> & { id?: string }) => Promise<void>;
  book?: Book | null;
  saving?: boolean;
}

type FormValues = {
  bookTitle: string; grade: string; subject: string; district: string;
  distributor: string; distributionDate: string; numberOfCopies: number;
};

export default function BookFormModal({ open, onClose, onSave, book, saving }: Props) {
  const { register, handleSubmit, setValue, watch, reset, formState: { errors } } = useForm<FormValues>();

  useEffect(() => {
    if (open) {
      reset({
        bookTitle: book?.bookTitle ?? '',
        grade: book?.grade ?? '',
        subject: book?.subject ?? '',
        district: book?.district ?? '',
        distributor: book?.distributor ?? '',
        distributionDate: book?.distributionDate ?? '',
        numberOfCopies: book?.numberOfCopies ?? 1,
      });
    }
  }, [open, book, reset]);

  const onSubmit = async (data: FormValues) => {
    await onSave({ ...data, numberOfCopies: Number(data.numberOfCopies), id: book?.id });
  };

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className="max-w-lg w-full max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{book ? 'Edit Book' : 'Add New Book'}</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <div>
            <Label>Book Title *</Label>
            <Input {...register('bookTitle', { required: true })} placeholder="Enter book title" className={errors.bookTitle ? 'border-destructive' : ''} />
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <Label>Grade *</Label>
              <Select value={watch('grade')} onValueChange={(v) => setValue('grade', v)}>
                <SelectTrigger><SelectValue placeholder="Select grade" /></SelectTrigger>
                <SelectContent>{GRADES.map((g) => <SelectItem key={g} value={g}>{g}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>Subject *</Label>
              <Select value={watch('subject')} onValueChange={(v) => setValue('subject', v)}>
                <SelectTrigger><SelectValue placeholder="Select subject" /></SelectTrigger>
                <SelectContent>{SUBJECTS.map((s) => <SelectItem key={s} value={s}>{s}</SelectItem>)}</SelectContent>
              </Select>
            </div>
          </div>
          <div>
            <Label>District *</Label>
            <Select value={watch('district')} onValueChange={(v) => setValue('district', v)}>
              <SelectTrigger><SelectValue placeholder="Select district" /></SelectTrigger>
              <SelectContent className="max-h-56">{DISTRICTS.map((d) => <SelectItem key={d} value={d}>{d}</SelectItem>)}</SelectContent>
            </Select>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <Label>Distributor *</Label>
              <Input {...register('distributor', { required: true })} placeholder="Name of distributor" />
            </div>
            <div>
              <Label>Number of Copies *</Label>
              <Input type="number" min={1} {...register('numberOfCopies', { required: true, min: 1 })} />
            </div>
          </div>
          <div>
            <Label>Distribution Date *</Label>
            <Input type="date" {...register('distributionDate', { required: true })} />
          </div>
          <DialogFooter className="gap-2">
            <Button type="button" variant="outline" onClick={onClose} disabled={saving}>Cancel</Button>
            <Button type="submit" disabled={saving}>{saving ? 'Saving...' : book ? 'Update' : 'Add Book'}</Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useRef } from 'react';
import { Button } from '@/components/ui/button';
import { Upload, Download } from 'lucide-react';
import { importBooks } from 'zite-endpoints-sdk';
import { toast } from 'sonner';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];

interface Props {
  books: Book[];
  onImported: () => void;
}

export default function CSVTools({ books, onImported }: Props) {
  const fileRef = useRef<HTMLInputElement>(null);

  const handleExport = () => {
    const headers = ['Book Title', 'Grade', 'Subject', 'District', 'Distributor', 'Distribution Date', 'Number of Copies'];
    const rows = books.map((b) => [
      `"${(b.bookTitle ?? '').replace(/"/g, '""')}"`,
      b.grade ?? '',
      b.subject ?? '',
      b.district ?? '',
      `"${(b.distributor ?? '').replace(/"/g, '""')}"`,
      b.distributionDate ?? '',
      b.numberOfCopies ?? 0,
    ]);
    const csv = [headers.join(','), ...rows.map((r) => r.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `learning-resource-inventory-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success(`Exported ${books.length} books`);
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const text = await file.text();
    const lines = text.split('\n').filter((l) => l.trim());
    if (lines.length < 2) { toast.error('CSV file is empty or invalid'); return; }

    const parsed = lines.slice(1).map((line) => {
      const cols = line.split(',').map((c) => c.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
      return {
        bookTitle: cols[0] ?? '',
        grade: cols[1] ?? '',
        subject: cols[2] ?? '',
        district: cols[3] ?? '',
        distributor: cols[4] ?? '',
        distributionDate: cols[5] ?? '',
        numberOfCopies: Number(cols[6]) || 0,
      };
    }).filter((b) => b.bookTitle);

    if (parsed.length === 0) { toast.error('No valid rows found in CSV'); return; }

    try {
      const result = await importBooks({ books: parsed });
      toast.success(`Imported ${result.imported} books successfully`);
      onImported();
    } catch {
      toast.error('Import failed. Please check your CSV format.');
    }
    e.target.value = '';
  };

  return (
    <div className="flex gap-2">
      <input ref={fileRef} type="file" accept=".csv" className="hidden" onChange={handleImport} />
      <Button variant="outline" size="sm" onClick={() => fileRef.current?.click()} className="flex items-center gap-1">
        <Upload className="h-4 w-4" />
        <span className="hidden sm:inline">Import CSV</span>
      </Button>
      <Button variant="outline" size="sm" onClick={handleExport} className="flex items-center gap-1">
        <Download className="h-4 w-4" />
        <span className="hidden sm:inline">Export CSV</span>
      </Button>
    </div>
  );
}

import { useState } from 'react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Pencil, Trash2, Plus, Search } from 'lucide-react';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Skeleton } from '@/components/ui/skeleton';
import CSVTools from './CSVTools';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];

interface Props {
  books: Book[];
  loading: boolean;
  onAdd: () => void;
  onEdit: (book: Book) => void;
  onDelete: (id: string) => Promise<void>;
  onRefresh: () => void;
}

export default function BookTable({ books, loading, onAdd, onEdit, onDelete, onRefresh }: Props) {
  const [search, setSearch] = useState('');
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [deleting, setDeleting] = useState(false);

  const filtered = books
    .filter((b) => (b.bookTitle ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.subject ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.district ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.distributor ?? '').toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? ''));

  const handleDelete = async () => {
    if (!deleteId) return;
    setDeleting(true);
    await onDelete(deleteId);
    setDeleting(false);
    setDeleteId(null);
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row gap-2 items-start sm:items-center justify-between">
        <div className="relative w-full sm:w-72">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input className="pl-9" placeholder="Search books..." value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>
        <div className="flex gap-2 items-center flex-wrap">
          <CSVTools books={books} onImported={onRefresh} />
          <Button size="sm" onClick={onAdd} className="flex items-center gap-1">
            <Plus className="h-4 w-4" /> Add Book
          </Button>
        </div>
      </div>

      <div className="text-sm text-muted-foreground">{filtered.length} book{filtered.length !== 1 ? 's' : ''} found</div>

      {loading ? (
        <div className="space-y-2">{Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-14 w-full rounded-lg" />)}</div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground">
          <p className="text-lg font-medium">No books found</p>
          <p className="text-sm mt-1">{search ? 'Try a different search term' : 'Add your first book to get started'}</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-lg border border-border">
          <table className="w-full text-sm">
            <thead className="bg-muted">
              <tr>
                {['Book Title', 'Grade', 'Subject', 'District', 'Distributor', 'Date', 'Copies', ''].map((h) => (
                  <th key={h} className="text-left px-3 py-2.5 font-semibold text-muted-foreground whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {filtered.map((book) => (
                <tr key={book.id} className="hover:bg-muted/40 transition-colors">
                  <td className="px-3 py-2.5 font-medium max-w-[180px] truncate">{book.bookTitle}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap"><Badge variant="outline" className="text-xs">{book.grade}</Badge></td>
                  <td className="px-3 py-2.5 max-w-[140px] truncate text-muted-foreground">{book.subject}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap text-muted-foreground">{book.district}</td>
                  <td className="px-3 py-2.5 max-w-[120px] truncate">{book.distributor}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap text-muted-foreground">{book.distributionDate ? new Date(book.distributionDate).toLocaleDateString() : '—'}</td>
                  <td className="px-3 py-2.5 text-center font-semibold">{book.numberOfCopies?.toLocaleString()}</td>
                  <td className="px-3 py-2.5">
                    <div className="flex gap-1 justify-end">
                      <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => onEdit(book)}><Pencil className="h-3.5 w-3.5" /></Button>
                      <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive" onClick={() => setDeleteId(book.id)}><Trash2 className="h-3.5 w-3.5" /></Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <AlertDialog open={!!deleteId} onOpenChange={(v) => !v && setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Book</AlertDialogTitle>
            <AlertDialogDescription>Are you sure you want to delete this book? This action cannot be undone.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} disabled={deleting} className="bg-destructive hover:bg-destructive/90">
              {deleting ? 'Deleting...' : 'Delete'}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Badge } from '@/components/ui/badge';
import { Label } from '@/components/ui/label';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { SUBJECTS, DISTRICTS, DATE_RANGE_OPTIONS } from '@/lib/constants';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];

interface Props { books: Book[] }

function getDateFilter(range: string): Date | null {
  const now = new Date();
  if (range === '7days') return new Date(now.setDate(now.getDate() - 7));
  if (range === 'month') return new Date(now.setMonth(now.getMonth() - 1));
  if (range === 'quarter') return new Date(now.setMonth(now.getMonth() - 3));
  if (range === 'year') return new Date(now.setFullYear(now.getFullYear() - 1));
  return null;
}

export default function ReportsView({ books }: Props) {
  const [dateRange, setDateRange] = useState('all');
  const [district, setDistrict] = useState('all');
  const [subject, setSubject] = useState('all');

  const filtered = useMemo(() => {
    const cutoff = getDateFilter(dateRange);
    return books.filter((b) => {
      if (cutoff && b.distributionDate && new Date(b.distributionDate) < cutoff) return false;
      if (district !== 'all' && b.district !== district) return false;
      if (subject !== 'all' && b.subject !== subject) return false;
      return true;
    });
  }, [books, dateRange, district, subject]);

  const totalCopies = filtered.reduce((s, b) => s + (b.numberOfCopies ?? 0), 0);
  const totalBooks = filtered.length;

  const bySubject = useMemo(() => SUBJECTS.map((s) => ({
    name: s.length > 12 ? s.slice(0, 12) + '…' : s,
    fullName: s,
    copies: filtered.filter((b) => b.subject === s).reduce((acc, b) => acc + (b.numberOfCopies ?? 0), 0),
  })).filter((x) => x.copies > 0), [filtered]);

  const byDistrict = useMemo(() => {
    const map: Record<string, number> = {};
    filtered.forEach((b) => { if (b.district) map[b.district] = (map[b.district] ?? 0) + (b.numberOfCopies ?? 0); });
    return Object.entries(map).map(([name, copies]) => ({ name, copies })).sort((a, b) => b.copies - a.copies).slice(0, 15);
  }, [filtered]);

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader><CardTitle className="text-base">Filters</CardTitle></CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
            <div><Label className="mb-1 block">Date Range</Label>
              <Select value={dateRange} onValueChange={setDateRange}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{DATE_RANGE_OPTIONS.map((o) => <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">District</Label>
              <Select value={district} onValueChange={setDistrict}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent className="max-h-56">
                  <SelectItem value="all">All Districts</SelectItem>
                  {DISTRICTS.map((d) => <SelectItem key={d} value={d}>{d}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">Subject</Label>
              <Select value={subject} onValueChange={setSubject}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>
                  <SelectItem value="all">All Subjects</SelectItem>
                  {SUBJECTS.map((s) => <SelectItem key={s} value={s}>{s}</SelectItem>)}
                </SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
        <Card><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-primary">{totalBooks}</p><p className="text-sm text-muted-foreground mt-1">Total Books</p></CardContent></Card>
        <Card><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-primary">{totalCopies.toLocaleString()}</p><p className="text-sm text-muted-foreground mt-1">Total Copies</p></CardContent></Card>
        <Card className="col-span-2 sm:col-span-1"><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-primary">{byDistrict.length}</p><p className="text-sm text-muted-foreground mt-1">Districts Covered</p></CardContent></Card>
      </div>

      {bySubject.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Copies Distributed by Subject</CardTitle></CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={220}>
              <BarChart data={bySubject} margin={{ top: 5, right: 10, left: 0, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                <XAxis dataKey="name" tick={{ fontSize: 11 }} />
                <YAxis tick={{ fontSize: 11 }} />
                <Tooltip formatter={(v, _, p) => [v, p.payload.fullName]} />
                <Bar dataKey="copies" className="fill-primary" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      )}

      {byDistrict.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Top Districts by Copies Distributed</CardTitle></CardHeader>
          <CardContent>
            <div className="space-y-2">
              {byDistrict.map((d) => (
                <div key={d.name} className="flex items-center gap-3">
                  <span className="w-24 text-sm text-muted-foreground shrink-0">{d.name}</span>
                  <div className="flex-1 bg-muted rounded-full h-5 overflow-hidden">
                    <div className="bg-primary h-full rounded-full transition-all" style={{ width: `${(d.copies / (byDistrict[0]?.copies || 1)) * 100}%` }} />
                  </div>
                  <span className="text-sm font-semibold w-16 text-right">{d.copies.toLocaleString()}</span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {filtered.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Distribution Details ({filtered.length} records)</CardTitle></CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-muted">
                  <tr>{['Book Title', 'Grade', 'Subject', 'District', 'Distributor', 'Date', 'Copies'].map((h) => (
                    <th key={h} className="text-left px-3 py-2 font-semibold text-muted-foreground whitespace-nowrap">{h}</th>
                  ))}</tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {[...filtered].sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? '')).map((b) => (
                    <tr key={b.id} className="hover:bg-muted/40">
                      <td className="px-3 py-2 font-medium max-w-[160px] truncate">{b.bookTitle}</td>
                      <td className="px-3 py-2"><Badge variant="outline" className="text-xs">{b.grade}</Badge></td>
                      <td className="px-3 py-2 text-muted-foreground max-w-[130px] truncate">{b.subject}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.district}</td>
                      <td className="px-3 py-2 max-w-[110px] truncate">{b.distributor}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.distributionDate ? new Date(b.distributionDate).toLocaleDateString() : '—'}</td>
                      <td className="px-3 py-2 text-right font-semibold">{b.numberOfCopies?.toLocaleString()}</td>
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-muted font-semibold">
                  <tr>
                    <td colSpan={6} className="px-3 py-2 text-right">Total Copies:</td>
                    <td className="px-3 py-2 text-right">{totalCopies.toLocaleString()}</td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </CardContent>
        </Card>
      )}

      {filtered.length === 0 && (
        <div className="text-center py-12 text-muted-foreground">
          <p className="text-lg font-medium">No data for selected filters</p>
          <p className="text-sm mt-1">Try adjusting your filter criteria</p>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { getBooks, saveBook, deleteBook } from 'zite-endpoints-sdk';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';
import NavHeader from '@/components/NavHeader';
import BookTable from '@/components/BookTable';
import BookFormModal from '@/components/BookFormModal';
import ReportsView from '@/components/ReportsView';
import { Toaster } from '@/components/ui/sonner';
import { toast } from 'sonner';

type Book = GetBooksOutputType['books'][0];

export default function InventoryPage() {
  const [activeTab, setActiveTab] = useState<'inventory' | 'reports'>('inventory');
  const [books, setBooks] = useState<Book[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editBook, setEditBook] = useState<Book | null>(null);
  const [saving, setSaving] = useState(false);

  const fetchBooks = useCallback(async () => {
    setLoading(true);
    try {
      const result = await getBooks({});
      setBooks(result.books);
    } catch {
      toast.error('Failed to load books');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => { fetchBooks(); }, [fetchBooks]);

  const handleSave = async (data: Omit<Book, 'id'> & { id?: string }) => {
    setSaving(true);
    try {
      await saveBook({
        ...data,
        bookTitle: data.bookTitle ?? '',
        grade: data.grade ?? '',
        subject: data.subject ?? '',
        district: data.district ?? '',
        distributor: data.distributor ?? '',
        distributionDate: data.distributionDate ?? '',
        numberOfCopies: data.numberOfCopies ?? 0,
      });
      toast.success(data.id ? 'Book updated!' : 'Book added!');
      setModalOpen(false);
      setEditBook(null);
      fetchBooks();
    } catch {
      toast.error('Failed to save book');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    await deleteBook({ id });
    toast.success('Book deleted');
    fetchBooks();
  };

  const handleEdit = (book: Book) => { setEditBook(book); setModalOpen(true); };
  const handleAdd = () => { setEditBook(null); setModalOpen(true); };

  return (
    <div className="min-h-screen bg-background">
      <Toaster />
      <NavHeader activeTab={activeTab} onTabChange={setActiveTab} />
      <main className="max-w-7xl mx-auto px-4 py-6">
        {activeTab === 'inventory' ? (
          <>
            <div className="mb-6">
              <h1 className="text-2xl font-bold text-foreground">Book Inventory</h1>
              <p className="text-muted-foreground text-sm mt-1">Manage your learning resource distribution records</p>
            </div>
            <BookTable
              books={books}
              loading={loading}
              onAdd={handleAdd}
              onEdit={handleEdit}
              onDelete={handleDelete}
              onRefresh={fetchBooks}
            />
          </>
        ) : (
          <>
            <div className="mb-6">
              <h1 className="text-2xl font-bold text-foreground">Distribution Reports</h1>
              <p className="text-muted-foreground text-sm mt-1">Analyze book distribution across grades, subjects, and districts</p>
            </div>
            <ReportsView books={books} />
          </>
        )}
      </main>

      <BookFormModal
        open={modalOpen}
        onClose={() => { setModalOpen(false); setEditBook(null); }}
        onSave={handleSave}
        book={editBook}
        saving={saving}
      />
    </div>
  );
}

import { useEffect } from 'react';
import { useAuth } from 'zite-auth-sdk';
import { BookOpen } from 'lucide-react';

export default function LoginPage() {
  const { loginWithRedirect } = useAuth();

  useEffect(() => {
    loginWithRedirect({ redirectUrl: window.location.origin + '/inventory' });
  }, [loginWithRedirect]);

  return (
    <div className="min-h-screen bg-background flex items-center justify-center">
      <div className="text-center space-y-4">
        <div className="flex justify-center">
          <div className="bg-primary rounded-full p-4">
            <BookOpen className="h-8 w-8 text-primary-foreground" />
          </div>
        </div>
        <h1 className="text-2xl font-bold">Learning Resource Inventory</h1>
        <p className="text-muted-foreground">Redirecting to login...</p>
      </div>
    </div>
  );
}

import { useEffect } from 'react';
import { BrowserRouter, Routes, Route, Navigate, useNavigate } from 'react-router-dom';
import { useAuth } from 'zite-auth-sdk';
import LoginPage from './pages/LoginPage';
import InventoryPage from './pages/InventoryPage';

function AuthGuard({ children }: { children: React.ReactNode }) {
  const { user, isLoading, loginWithRedirect } = useAuth();
  const navigate = useNavigate();

  useEffect(() => {
    if (!isLoading && !user) {
      loginWithRedirect({ redirectUrl: window.location.href });
    }
  }, [isLoading, user, loginWithRedirect, navigate]);

  if (isLoading) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <div className="text-center space-y-3">
          <div className="animate-spin rounded-full h-10 w-10 border-2 border-primary border-t-transparent mx-auto" />
          <p className="text-muted-foreground text-sm">Loading...</p>
        </div>
      </div>
    );
  }

  if (!user) return null;
  return <>{children}</>;
}

export default function App() {
  return (
    <BrowserRouter>
      <Routes>
        <Route path="/login" element={<LoginPage />} />
        <Route path="/inventory" element={<AuthGuard><InventoryPage /></AuthGuard>} />
        <Route path="*" element={<Navigate to="/inventory" replace />} />
      </Routes>
    </BrowserRouter>
  );
}

