import { useState, useEffect, useCallback } from 'react';
import { getBooks, saveBook, deleteBook } from 'zite-endpoints-sdk';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';
import NavHeader from '@/components/NavHeader';
import BookTable from '@/components/BookTable';
import BookFormModal from '@/components/BookFormModal';
import ReportsView from '@/components/ReportsView';
import { Toaster } from '@/components/ui/sonner';
import { toast } from 'sonner';
type Book = GetBooksOutputType['books'][0];
export default function InventoryPage() {
  const [activeTab, setActiveTab] = useState<'inventory' | 'reports'>('inventory');
  const [books, setBooks] = useState<Book[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editBook, setEditBook] = useState<Book | null>(null);
  const [saving, setSaving] = useState(false);
  const fetchBooks = useCallback(async () => {
    setLoading(true);
    try {
      const result = await getBooks({});
      setBooks(result.books);
    } catch {
      toast.error('Failed to load books');
    } finally {
      setLoading(false);
    }
  }, []);
  useEffect(() => {
    fetchBooks();
  }, [fetchBooks]);
  const handleSave = async (data: Omit<Book, 'id'> & {
    id?: string;
  }) => {
    setSaving(true);
    try {
      await saveBook({
        ...data,
        bookTitle: data.bookTitle ?? '',
        grade: data.grade ?? '',
        subject: data.subject ?? '',
        district: data.district ?? '',
        distributor: data.distributor ?? '',
        distributionDate: data.distributionDate ?? '',
        numberOfCopies: data.numberOfCopies ?? 0
      });
      toast.success(data.id ? 'Book updated!' : 'Book added!');
      setModalOpen(false);
      setEditBook(null);
      fetchBooks();
    } catch {
      toast.error('Failed to save book');
    } finally {
      setSaving(false);
    }
  };
  const handleDelete = async (id: string) => {
    await deleteBook({
      id
    });
    toast.success('Book deleted');
    fetchBooks();
  };
  const handleEdit = (book: Book) => {
    setEditBook(book);
    setModalOpen(true);
  };
  const handleAdd = () => {
    setEditBook(null);
    setModalOpen(true);
  };
  return <div className="min-h-screen bg-background">
      <Toaster />
      <NavHeader activeTab={activeTab} onTabChange={setActiveTab} />
      <main className="max-w-7xl mx-auto px-4 py-6">
        {activeTab === 'inventory' ? <>
            <div className="mb-6">
              <h1 className="text-2xl font-bold text-foreground">Book Inventory</h1>
              <p className='text-muted-foreground text-sm mt-1'>Manage your learning resource distribution records</p>
            </div>
            <BookTable books={books} loading={loading} onAdd={handleAdd} onEdit={handleEdit} onDelete={handleDelete} onRefresh={fetchBooks} />
          </> : <>
            <div className="mb-6">
              <h1 className="text-2xl font-bold text-foreground">Distribution Reports</h1>
              <p className="text-muted-foreground text-sm mt-1">Analyze book distribution across grades, subjects, and districts</p>
            </div>
            <ReportsView books={books} />
          </>}
      </main>

      <BookFormModal open={modalOpen} onClose={() => {
      setModalOpen(false);
      setEditBook(null);
    }} onSave={handleSave} book={editBook} saving={saving} />
    </div>;
}

