import { LogOut, BarChart2, List } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useAuth } from 'zite-auth-sdk';
import { useState } from 'react';

function GoogleAvatar({ email, firstName }: { email?: string; firstName?: string }) {
  const [imgError, setImgError] = useState(false);
  const initial = firstName ? firstName[0].toUpperCase() : email?.[0].toUpperCase() ?? '?';
  const googlePhotoUrl = email
    ? `https://www.google.com/s2/photos/profile/${encodeURIComponent(email)}`
    : null;

  if (!imgError && googlePhotoUrl) {
    return (
      <img
        src={googlePhotoUrl}
        alt={initial}
        referrerPolicy="no-referrer"
        onError={() => setImgError(true)}
        className="h-8 w-8 rounded-full object-cover shrink-0 ring-2 ring-primary-foreground/30"
      />
    );
  }

  return (
    <div className="h-8 w-8 rounded-full bg-primary-foreground/20 ring-2 ring-primary-foreground/30 flex items-center justify-center text-xs font-bold shrink-0">
      {initial}
    </div>
  );
}

