/** Filter operators for querying records (Prisma-style) */
type FilterOperators<T> = {
  not?: T;
  in?: T[];
  notIn?: T[];
  lt?: number | Date;
  lte?: number | Date;
  gt?: number | Date;
  gte?: number | Date;
  contains?: any;
} | T;

/** Filter type for record queries - use field names as keys with FilterOperators or direct values for equality */
type RecordFilters<T> = { [K in keyof T]?: FilterOperators<T[K]> };

/** Helper type to infer schema output type */
type InferSchemaType<T> = T extends { _output: infer U } ? U : T;

