export default function BookFormModal({ open, onClose, onSave, book, saving }: Props) {
  const { register, handleSubmit, setValue, watch, reset, formState: { errors } } = useForm<FormValues>();

  useEffect(() => {
    if (open) {
      reset({
        bookTitle: book?.bookTitle ?? '',
        grade: book?.grade ?? '',
        subject: book?.subject ?? '',
        district: book?.district ?? '',
        schoolName: book?.schoolName ?? '',
        distributor: book?.distributor ?? '',
        distributionDate: book?.distributionDate ?? '',
        numberOfCopies: book?.numberOfCopies ?? 1,
        numberOfCopiesRemaining: book?.numberOfCopiesRemaining ?? 0,
