type Book = GetBooksOutputType['books'][0];

interface Props {
  books: Book[];
  loading: boolean;
  onAdd: () => void;
  onEdit: (book: Book) => void;
  onDelete: (id: string) => Promise<void>;
  onRefresh: () => void;
}

export default function BookTable({ books, loading, onAdd, onEdit, onDelete, onRefresh }: Props) {
  const [search, setSearch] = useState('');
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [deleting, setDeleting] = useState(false);

  const filtered = books
    .filter((b) =>
      (b.bookTitle ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.subject ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.district ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.schoolName ?? '').toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? ''));

  const handleDelete = async () => {
    if (!deleteId) return;
    setDeleting(true);
    await onDelete(deleteId);
    setDeleting(false);
    setDeleteId(null);
  };

  const getRemainingColor = (remaining?: number, total?: number) => {
    if (remaining == null || total == null || total === 0) return '';
    const ratio = remaining / total;
    if (ratio <= 0) return 'text-destructive font-bold';
    if (ratio <= 0.25) return 'text-orange-600 font-semibold';
    return 'text-green-700 font-semibold';
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row gap-2 items-start sm:items-center justify-between">
        <div className="relative w-full sm:w-72">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input className="pl-9" placeholder="Search books, school, district..." value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>
        <div className="flex gap-2 items-center flex-wrap">
          <CSVTools books={books} onImported={onRefresh} />
          <Button size="sm" onClick={onAdd} className="flex items-center gap-1">
            <Plus className="h-4 w-4" /> Add Book
          </Button>
        </div>
      </div>

      <div className="text-sm text-muted-foreground">{filtered.length} book{filtered.length !== 1 ? 's' : ''} found</div>

      {loading ? (
        <div className="space-y-2">{Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-14 w-full rounded-lg" />)}</div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground">
          <p className="text-lg font-medium">No books found</p>
          <p className="text-sm mt-1">{search ? 'Try a different search term' : 'Add your first book to get started'}</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-lg border border-border">
          <table className="w-full text-sm">
            <thead className="bg-muted">
              <tr>
                {['Book Title', 'Grade', 'Subject', 'District', 'School Name', 'Date', 'Copies', 'Remaining', ''].map((h) => (
                  <th key={h} className="text-left px-3 py-2.5 font-semibold text-muted-foreground whitespace-nowrap">{h}</th>
                ))}
              </tr>
            </thead>
            <tbody className="divide-y divide-border">
              {filtered.map((book) => (
                <tr key={book.id} className="hover:bg-muted/40 transition-colors">
                  <td className="px-3 py-2.5 font-medium max-w-[160px] truncate">{book.bookTitle}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap"><Badge variant="outline" className="text-xs">{book.grade}</Badge></td>
                  <td className="px-3 py-2.5 max-w-[130px] truncate text-muted-foreground">{book.subject}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap text-muted-foreground">{book.district}</td>
                  <td className="px-3 py-2.5 max-w-[150px] truncate">{book.schoolName ?? '—'}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap text-muted-foreground">{book.distributionDate ? new Date(book.distributionDate).toLocaleDateString() : '—'}</td>
                  <td className="px-3 py-2.5 text-center font-semibold">{book.numberOfCopies?.toLocaleString() ?? '—'}</td>
                  <td className={`px-3 py-2.5 text-center ${getRemainingColor(book.numberOfCopiesRemaining, book.numberOfCopies)}`}>
                    {book.numberOfCopiesRemaining?.toLocaleString() ?? '—'}
                  </td>
                  <td className="px-3 py-2.5">
                    <div className="flex gap-1 justify-end">
                      <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => onEdit(book)}><Pencil className="h-3.5 w-3.5" /></Button>
                      <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive" onClick={() => setDeleteId(book.id)}><Trash2 className="h-3.5 w-3.5" /></Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <AlertDialog open={!!deleteId} onOpenChange={(v) => !v && setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader>
            <AlertDialogTitle>Delete Book</AlertDialogTitle>
            <AlertDialogDescription>Are you sure you want to delete this book? This action cannot be undone.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} disabled={deleting} className="bg-destructive hover:bg-destructive/90">
              {deleting ? 'Deleting...' : 'Delete'}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useRef } from 'react';
import { Button } from '@/components/ui/button';
import { Upload, Download } from 'lucide-react';
import { importBooks } from 'zite-endpoints-sdk';
import { toast } from 'sonner';
import type { GetBooksOutputType, ImportBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];

interface Props {
  books: Book[];
  onImported: () => void;
}

export default function CSVTools({ books, onImported }: Props) {
  const fileRef = useRef<HTMLInputElement>(null);

  const handleExport = () => {
    const headers = ['Book Title', 'Grade', 'Subject', 'District', 'School Name', 'Distributor', 'Distribution Date', 'Number of Copies', 'Copies Remaining'];
    const rows = books.map((b) => [
      `"${(b.bookTitle ?? '').replace(/"/g, '""')}"`,
      b.grade ?? '',
      b.subject ?? '',
      b.district ?? '',
      `"${(b.schoolName ?? '').replace(/"/g, '""')}"`,
      `"${(b.distributor ?? '').replace(/"/g, '""')}"`,
      b.distributionDate ?? '',
      b.numberOfCopies ?? 0,
      b.numberOfCopiesRemaining ?? 0,
    ]);
    const csv = [headers.join(','), ...rows.map((r) => r.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `learning-resource-inventory-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success(`Exported ${books.length} books`);
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const text = await file.text();
    const lines = text.split('\n').filter((l) => l.trim());
    if (lines.length < 2) { toast.error('CSV file is empty or invalid'); return; }

    const parsed = lines.slice(1).map((line) => {
      const cols = line.split(',').map((c) => c.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
      return {
        bookTitle: cols[0] ?? '',
        grade: cols[1] ?? '',
        subject: cols[2] ?? '',
        district: cols[3] ?? '',
        schoolName: cols[4] ?? '',
        distributor: cols[5] ?? '',
        distributionDate: cols[6] ?? '',
        numberOfCopies: Number(cols[7]) || 0,
        numberOfCopiesRemaining: Number(cols[8]) || 0,
      };
    }).filter((b) => b.bookTitle);

    if (parsed.length === 0) { toast.error('No valid rows found in CSV'); return; }

    try {
      const result = await importBooks({ books: parsed });
      const msg = result.skipped > 0
        ? `Imported ${result.imported} books (${result.skipped} skipped — duplicate titles)`
        : `Imported ${result.imported} books successfully`;
      toast.success(msg);
      onImported();
    } catch {
      toast.error('Import failed. Please check your CSV format.');
    }
    e.target.value = '';
  };

  return (
    <div className="flex gap-2">
      <input ref={fileRef} type="file" accept=".csv" className="hidden" onChange={handleImport} />
      <Button variant="outline" size="sm" onClick={() => fileRef.current?.click()} className="flex items-center gap-1">
        <Upload className="h-4 w-4" />
        <span className="hidden sm:inline">Import CSV</span>
      </Button>
      <Button variant="outline" size="sm" onClick={handleExport} className="flex items-center gap-1">
        <Download className="h-4 w-4" />
        <span className="hidden sm:inline">Export CSV</span>
      </Button>
    </div>
  );
}

