import { useRef } from 'react';
import { Button } from '@/components/ui/button';
import { Upload, Download } from 'lucide-react';
import { importBooks } from 'zite-endpoints-sdk';
import { toast } from 'sonner';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];

interface Props {
  books: Book[];
  onImported: () => void;
}

export default function CSVTools({ books, onImported }: Props) {
  const fileRef = useRef<HTMLInputElement>(null);

  const handleExport = () => {
    const headers = ['Book Title', 'Grade', 'Subject', 'District', 'School Name', 'Distributor', 'Distribution Date', 'Total Copies', 'Copies Distributed', 'Copies Remaining'];
    const rows = books.map((b) => [
      `"${(b.bookTitle ?? '').replace(/"/g, '""')}"`,
      b.grade ?? '',
      b.subject ?? '',
      b.district ?? '',
      `"${(b.schoolName ?? '').replace(/"/g, '""')}"`,
      `"${(b.distributor ?? '').replace(/"/g, '""')}"`,
      b.distributionDate ?? '',
      b.numberOfCopies ?? 0,
      b.numberOfCopiesDistributed ?? 0,
      b.numberOfCopiesRemaining ?? 0,
    ]);
    const csv = [headers.join(','), ...rows.map((r) => r.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `learning-resource-inventory-${new Date().toISOString().split('T')[0]}.csv`;
    a.click();
    URL.revokeObjectURL(url);
    toast.success(`Exported ${books.length} books`);
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const text = await file.text();
    const lines = text.split('\n').filter((l) => l.trim());
    if (lines.length < 2) { toast.error('CSV file is empty or invalid'); return; }

    const parsed = lines.slice(1).map((line) => {
      const cols = line.split(',').map((c) => c.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
      return {
        bookTitle: cols[0] ?? '',
        grade: cols[1] ?? '',
        subject: cols[2] ?? '',
        district: cols[3] ?? '',
        schoolName: cols[4] ?? '',
        distributor: cols[5] ?? '',
        distributionDate: cols[6] ?? '',
        numberOfCopies: Number(cols[7]) || 0,
        numberOfCopiesDistributed: Number(cols[8]) || 0,
      };
    }).filter((b) => b.bookTitle);

    if (parsed.length === 0) { toast.error('No valid rows found in CSV'); return; }

    try {
      const result = await importBooks({ books: parsed });
      const msg = result.skipped > 0
        ? `Imported ${result.imported} books (${result.skipped} skipped — duplicate titles)`
        : `Imported ${result.imported} books successfully`;
      toast.success(msg);
      onImported();
    } catch {
      toast.error('Import failed. Please check your CSV format.');
    }
    e.target.value = '';
  };

  return (
    <div className="flex gap-2">
      <input ref={fileRef} type="file" accept=".csv" className="hidden" onChange={handleImport} />
      <Button variant="outline" size="sm" onClick={() => fileRef.current?.click()} className="flex items-center gap-1">
        <Upload className="h-4 w-4" />
        <span className="hidden sm:inline">Import CSV</span>
      </Button>
      <Button variant="outline" size="sm" onClick={handleExport} className="flex items-center gap-1">
        <Download className="h-4 w-4" />
        <span className="hidden sm:inline">Export CSV</span>
      </Button>
    </div>
  );
}

