  onAdd: () => void;
  onEdit: (book: Book) => void;
  onDelete: (id: string) => Promise<void>;
  onRefresh: () => void;
}

function remainingClass(remaining?: number, total?: number) {
  if (remaining == null || total == null || total === 0) return 'text-center';
  if (remaining === 0) return 'text-center text-destructive font-bold';
  if (remaining / total <= 0.25) return 'text-center text-orange-600 font-semibold';
  return 'text-center text-green-700 font-semibold';
}

export default function BookTable({ books, loading, onAdd, onEdit, onDelete, onRefresh }: Props) {
  const [search, setSearch] = useState('');
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [deleting, setDeleting] = useState(false);

  const filtered = books
    .filter((b) =>
      (b.bookTitle ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.subject ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.district ?? '').toLowerCase().includes(search.toLowerCase()) ||
      (b.schoolName ?? '').toLowerCase().includes(search.toLowerCase()))
    .sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? ''));

  const handleDelete = async () => {
    if (!deleteId) return;
    setDeleting(true);
    await onDelete(deleteId);
    setDeleting(false);
    setDeleteId(null);
  };

