      ) : filtered.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground">
          <p className="text-lg font-medium">No books found</p>
          <p className="text-sm mt-1">{search ? 'Try a different search term' : 'Add your first book to get started'}</p>
