import { useEffect, useState } from 'react';
import { getBooks } from 'zite-endpoints-sdk';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { BookOpen, BookMarked, TrendingUp, AlertTriangle, Package } from 'lucide-react';
import { useAuth } from 'zite-auth-sdk';
import { SUBJECTS } from '@/lib/constants';
type Book = GetBooksOutputType['books'][0];
function StatCard({
  title,
  value,
  icon: Icon,
  sub
}: {
  title: string;
  value: string | number;
  icon: React.ElementType;
  sub?: string;
}) {
  return <Card>
      <CardContent className="pt-5 flex items-start justify-between gap-3">
        <div>
          <p className="text-sm text-muted-foreground">{title}</p>
          <p className="text-3xl font-bold text-foreground mt-1">{typeof value === 'number' ? value.toLocaleString() : value}</p>
          {sub && <p className="text-xs text-muted-foreground mt-1">{sub}</p>}
        </div>
        <div className="bg-primary/10 rounded-lg p-2.5 shrink-0">
          <Icon className="h-5 w-5 text-primary" />
        </div>
      </CardContent>
    </Card>;
}
export default function DashboardPage() {
  const {
    user
  } = useAuth();
  const [books, setBooks] = useState<Book[]>([]);
  const [loading, setLoading] = useState(true);
  useEffect(() => {
    getBooks({}).then(r => setBooks(r.books)).finally(() => setLoading(false));
  }, []);
  const totalBooks = books.length;
  const totalCopies = books.reduce((s, b) => s + (b.numberOfCopies ?? 0), 0);
  const totalDistributed = books.reduce((s, b) => s + (b.numberOfCopiesDistributed ?? 0), 0);
  const totalRemaining = books.reduce((s, b) => s + (b.numberOfCopiesRemaining ?? 0), 0);
  const lowStock = books.filter(b => {
    const r = b.numberOfCopiesRemaining ?? 0;
    const t = b.numberOfCopies ?? 0;
    return t > 0 && r / t <= 0.25;
  });
  const bySubject = SUBJECTS.map(s => ({
    name: s,
    count: books.filter(b => b.subject === s).length,
    distributed: books.filter(b => b.subject === s).reduce((acc, b) => acc + (b.numberOfCopiesDistributed ?? 0), 0)
  })).filter(s => s.count > 0).sort((a, b) => b.distributed - a.distributed);
  const firstName = user?.firstName || user?.email?.split('@')[0] || 'there';
  return <div className="space-y-6">
      <div>
        <h1 className='text-2xl font-bold text-primary'>Welcome back, {firstName}! 👋</h1>
        <p className="text-muted-foreground text-sm mt-1">Here's an overview of your learning resource inventory.</p>
      </div>

      {loading ? <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          {Array.from({
        length: 4
      }).map((_, i) => <Skeleton key={i} className="h-28 rounded-xl" />)}
        </div> : <div className="grid grid-cols-2 lg:grid-cols-4 gap-4">
          <StatCard title="Total Books" value={totalBooks} icon={BookOpen} />
          <StatCard title="Total Copies" value={totalCopies} icon={Package} />
          <StatCard title="Distributed" value={totalDistributed} icon={TrendingUp} />
          <StatCard title="Remaining" value={totalRemaining} icon={BookMarked} sub={lowStock.length > 0 ? `${lowStock.length} low stock` : undefined} />
        </div>}

      {!loading && lowStock.length > 0 && <Card className="border-orange-200 bg-orange-50">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm flex items-center gap-2 text-orange-700">
              <AlertTriangle className="h-4 w-4" /> Low Stock Alert ({lowStock.length} books)
            </CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-1.5">
              {lowStock.slice(0, 5).map(b => <div key={b.id} className="flex items-center justify-between text-sm">
                  <span className="font-medium text-foreground truncate max-w-[200px]">{b.bookTitle}</span>
                  <span className="text-orange-700 font-semibold shrink-0 ml-2">{b.numberOfCopiesRemaining} left</span>
                </div>)}
              {lowStock.length > 5 && <p className="text-xs text-orange-600 mt-1">+{lowStock.length - 5} more books</p>}
            </div>
          </CardContent>
        </Card>}

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <Card>
          <CardHeader><CardTitle className="text-base">Books by Subject</CardTitle></CardHeader>
          <CardContent>
            {loading ? <Skeleton className="h-40" /> : bySubject.length === 0 ? <p className="text-muted-foreground text-sm text-center py-6">No data yet</p> : <div className="space-y-3">
                {bySubject.map(s => <div key={s.name}>
                    <div className="flex items-center justify-between text-sm mb-1">
                      <span className="text-foreground font-medium truncate max-w-[180px]">{s.name}</span>
                      <span className="text-muted-foreground shrink-0 ml-2">{s.count} book{s.count !== 1 ? 's' : ''}</span>
                    </div>
                    <div className="h-2 bg-muted rounded-full overflow-hidden">
                      <div className="h-full bg-primary rounded-full transition-all" style={{
                  width: `${s.count / totalBooks * 100}%`
                }} />
                    </div>
                  </div>)}
              </div>}
          </CardContent>
        </Card>

        <Card>
          <CardHeader><CardTitle className="text-base">Recent Books</CardTitle></CardHeader>
          <CardContent>
            {loading ? <Skeleton className="h-40" /> : books.length === 0 ? <p className="text-muted-foreground text-sm text-center py-6">No books added yet</p> : <div className="space-y-3">
                {[...books].sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? '')).slice(0, 6).map(b => <div key={b.id} className="flex items-start justify-between gap-2 text-sm border-b border-border pb-2 last:border-0 last:pb-0">
                    <div className="overflow-hidden">
                      <p className="font-medium text-foreground truncate">{b.bookTitle}</p>
                      <p className="text-xs text-muted-foreground">{b.grade} · {b.subject}</p>
                    </div>
                    <div className="text-right shrink-0">
                      <p className="font-semibold text-foreground">{b.numberOfCopies?.toLocaleString()}</p>
                      <p className="text-xs text-muted-foreground">copies</p>
                    </div>
                  </div>)}
              </div>}
          </CardContent>
        </Card>
      </div>
    </div>;
}

