import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { SUBJECTS, GRADES, DISTRICTS } from '@/lib/constants';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];

interface Props {
  open: boolean;
  onClose: () => void;
  onSave: (data: Omit<Book, 'id'> & { id?: string }) => Promise<void>;
  book?: Book | null;
  saving?: boolean;
}

type FormValues = {
  bookTitle: string; grade: string; subject: string; district: string;
  schoolName: string; distributor: string; distributionDate: string;
  numberOfCopies: number; numberOfCopiesDistributed: number;
};

export default function BookFormModal({ open, onClose, onSave, book, saving }: Props) {
  const { register, handleSubmit, setValue, watch, reset, formState: { errors } } = useForm<FormValues>();

  useEffect(() => {
    if (open) {
      reset({
        bookTitle: book?.bookTitle ?? '',
        grade: book?.grade ?? '',
        subject: book?.subject ?? '',
        district: book?.district ?? '',
        schoolName: book?.schoolName ?? '',
        distributor: book?.distributor ?? '',
        distributionDate: book?.distributionDate ?? '',
        numberOfCopies: book?.numberOfCopies ?? 0,
        numberOfCopiesDistributed: book?.numberOfCopiesDistributed ?? 0,
      });
    }
  }, [open, book, reset]);

  const totalCopies = Number(watch('numberOfCopies') ?? 0);
  const distributed = Number(watch('numberOfCopiesDistributed') ?? 0);
  const remaining = Math.max(0, totalCopies - distributed);

  const onSubmit = async (data: FormValues) => {
    await onSave({
      ...data,
      numberOfCopies: Number(data.numberOfCopies),
      numberOfCopiesDistributed: Number(data.numberOfCopiesDistributed),
      numberOfCopiesRemaining: Math.max(0, Number(data.numberOfCopies) - Number(data.numberOfCopiesDistributed)),
      id: book?.id,
    });
  };

  const remainingColor = remaining === 0 ? 'text-destructive' : remaining / (totalCopies || 1) <= 0.25 ? 'text-orange-600' : 'text-green-700';

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className="max-w-lg w-full max-h-[90vh] overflow-y-auto">
        <DialogHeader>
          <DialogTitle>{book ? 'Edit Book' : 'Add New Book'}</DialogTitle>
        </DialogHeader>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-4">
          <div>
            <Label>Book Title *</Label>
            <Input {...register('bookTitle', { required: true })} placeholder="Enter book title"
              className={errors.bookTitle ? 'border-destructive' : ''} />
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <Label>Grade *</Label>
              <Select value={watch('grade')} onValueChange={(v) => setValue('grade', v)}>
                <SelectTrigger><SelectValue placeholder="Select grade" /></SelectTrigger>
                <SelectContent>{GRADES.map((g) => <SelectItem key={g} value={g}>{g}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>Subject *</Label>
              <Select value={watch('subject')} onValueChange={(v) => setValue('subject', v)}>
                <SelectTrigger><SelectValue placeholder="Select subject" /></SelectTrigger>
                <SelectContent>{SUBJECTS.map((s) => <SelectItem key={s} value={s}>{s}</SelectItem>)}</SelectContent>
              </Select>
            </div>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
            <div>
              <Label>District *</Label>
              <Select value={watch('district')} onValueChange={(v) => setValue('district', v)}>
                <SelectTrigger><SelectValue placeholder="Select district" /></SelectTrigger>
                <SelectContent className="max-h-56">{DISTRICTS.map((d) => <SelectItem key={d} value={d}>{d}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div>
              <Label>School Name *</Label>
              <Input {...register('schoolName', { required: true })} placeholder="e.g. Central Elementary School"
                className={errors.schoolName ? 'border-destructive' : ''} />
            </div>
          </div>
          <div>
            <Label>Distributor *</Label>
            <Input {...register('distributor', { required: true })} placeholder="Name of distributor" />
          </div>
          <div>
            <Label>Distribution Date *</Label>
            <Input type="date" {...register('distributionDate', { required: true })} />
          </div>

          {/* Copy counts */}
          <div className="grid grid-cols-3 gap-3">
            <div>
              <Label>Total Copies *</Label>
              <Input type="number" min={0} {...register('numberOfCopies', { required: true, min: 0 })} />
            </div>
            <div>
              <Label>Distributed *</Label>
              <Input type="number" min={0} {...register('numberOfCopiesDistributed', { required: true, min: 0 })} />
            </div>
            <div>
              <Label>Remaining</Label>
              <div className={`flex h-9 items-center rounded-md border border-border bg-muted px-3 text-sm font-bold ${remainingColor}`}>
                {remaining.toLocaleString()}
              </div>
              <p className="text-xs text-muted-foreground mt-1">Auto-calculated</p>
            </div>
          </div>

          <DialogFooter className="gap-2">
            <Button type="button" variant="outline" onClick={onClose} disabled={saving}>Cancel</Button>
            <Button type="submit" disabled={saving}>{saving ? 'Saving...' : book ? 'Update' : 'Add Book'}</Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { NavLink } from 'react-router-dom';
import { LayoutDashboard, BookOpen, BarChart2, LogOut, Menu, X, BookMarked } from 'lucide-react';
import { Button } from '@/components/ui/button';
import { useAuth } from 'zite-auth-sdk';
function GoogleAvatar({
  email,
  firstName,
  lastName
}: {
  email?: string;
  firstName?: string;
  lastName?: string;
}) {
  const [imgError, setImgError] = useState(false);
  const fullName = [firstName, lastName].filter(Boolean).join('+') || email?.split('@')[0] || 'User';
  const initial = firstName ? firstName[0].toUpperCase() : email?.[0].toUpperCase() ?? '?';
  const uiAvatarUrl = `https://ui-avatars.com/api/?name=${encodeURIComponent(fullName)}&size=64&bold=true&format=svg`;
  if (!imgError) {
    return <img src={uiAvatarUrl} alt={initial} onError={() => setImgError(true)} className="h-9 w-9 rounded-full object-cover shrink-0 ring-2 ring-primary/20" />;
  }
  return <div className="h-9 w-9 rounded-full bg-primary/10 ring-2 ring-primary/20 flex items-center justify-center text-sm font-bold text-primary shrink-0">{initial}</div>;
}
const navItems = [{
  to: '/dashboard',
  icon: LayoutDashboard,
  label: 'Dashboard'
}, {
  to: '/inventory',
  icon: BookOpen,
  label: 'Inventory'
}, {
  to: '/reports',
  icon: BarChart2,
  label: 'Reports'
}];
interface SidebarProps {
  onClose?: () => void;
}
function SidebarContent({
  onClose
}: SidebarProps) {
  const {
    user,
    logout
  } = useAuth();
  return <div className="flex flex-col h-full">
      {/* Logo */}
      <div className='flex items-center gap-2.5 px-4 py-4 border-b border-border bg-primary'>
        <img src="https://images.fillout.com/orgid-655049/flowpublicid-oaqakf9ezw/widgetid-default/hYBPspPccZdR4fdUnnX7gY/pasted-image-1776279176587.jpg" alt="LR Logo" className="h-9 w-9 rounded-full object-cover shrink-0" />
        <div className="leading-tight">
          <p className='font-bold text-center text-primary-foreground text-base'>Inventory for</p>
          <p className='font-bold text-primary-foreground text-base'>Learning Resource</p>
        </div>
      </div>

      {/* Nav items */}
      <nav className='flex-1 px-3 py-4 space-y-1 bg-primary'>
        {navItems.map(({
        to,
        icon: Icon,
        label
      }) => <NavLink key={to} to={to} onClick={onClose} className='flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors text-primary-foreground bg-[#4b77bd]' href='/dashboard'>
            <Icon className="h-4 w-4 shrink-0" />
            {label}
          </NavLink>)}
      </nav>

      {/* User profile + logout */}
      <div className="px-3 pb-4 border-t border-border pt-3 space-y-3">
        <div className="flex items-center gap-2.5 px-1">
          <GoogleAvatar email={user?.email} firstName={user?.firstName} lastName={user?.lastName} />
          <div className="flex flex-col leading-tight overflow-hidden">
            <span className="text-xs font-semibold truncate text-foreground">
              {user?.firstName || user?.lastName ? [user?.firstName, user?.lastName].filter(Boolean).join(' ') : user?.email}
            </span>
            <span className="text-xs text-muted-foreground truncate">{user?.email}</span>
          </div>
        </div>
        <Button variant="outline" size="sm" className="w-full flex items-center gap-2 text-muted-foreground" onClick={() => logout({
        returnTo: window.location.origin
      })}>
          <LogOut className="h-4 w-4" /> Logout
        </Button>
      </div>
    </div>;
}
export default function Sidebar() {
  const [mobileOpen, setMobileOpen] = useState(false);
  return <>
      {/* Mobile top bar */}
      <div className="lg:hidden fixed top-0 left-0 right-0 z-40 bg-background border-b border-border flex items-center px-4 h-14">
        <Button variant="ghost" size="icon" onClick={() => setMobileOpen(true)}><Menu className="h-5 w-5" /></Button>
        <div className="flex items-center gap-2 ml-3">
          <img src="https://images.fillout.com/orgid-655049/flowpublicid-oaqakf9ezw/widgetid-default/hYBPspPccZdR4fdUnnX7gY/pasted-image-1776279176587.jpg" alt="LR Logo" className="h-7 w-7 rounded-full object-cover" />
          <span className="font-bold text-sm text-foreground">Inventory for Learning Resource</span>
        </div>
      </div>

      {/* Mobile overlay */}
      {mobileOpen && <div className="lg:hidden fixed inset-0 z-50 flex">
          <div className="absolute inset-0 bg-black/40" onClick={() => setMobileOpen(false)} />
          <div className="relative w-64 bg-background h-full shadow-xl z-10">
            <Button variant="ghost" size="icon" className="absolute top-3 right-3" onClick={() => setMobileOpen(false)}><X className="h-4 w-4" /></Button>
            <SidebarContent onClose={() => setMobileOpen(false)} />
          </div>
        </div>}

      {/* Desktop sidebar */}
      <aside className="hidden lg:flex flex-col w-60 shrink-0 border-r border-border bg-background h-screen sticky top-0">
        <SidebarContent />
      </aside>
    </>;
}

