// Base SDK exports - always available

/** Filter operators for querying records (Prisma-style) */
type FilterOperators<T> = {
  not?: T;
  in?: T[];
  notIn?: T[];
  lt?: number | Date;
  lte?: number | Date;
  gt?: number | Date;
  gte?: number | Date;
  contains?: any;
} | T;

/** Filter type for record queries - use field names as keys with FilterOperators or direct values for equality */
type RecordFilters<T> = { [K in keyof T]?: FilterOperators<T[K]> };

/** Helper type to infer schema output type */
type InferSchemaType<T> = T extends { _output: infer U } ? U : T;

/** Stream interface for streaming endpoints */
type ZiteStreamInterface = {
  /** Write a chunk to the stream (sent to frontend in real-time) */
  write: (data: any) => Promise<void>;
  /** Forward an AsyncIterable to the stream and collect the result */
  forward: (asyncIterable: AsyncIterable<string>) => Promise<string>;
};

/** Error class for endpoint errors with typed error codes */
type ZiteErrorCode = 'BAD_REQUEST' | 'UNAUTHORIZED' | 'FORBIDDEN' | 'NOT_FOUND' | 'CONFLICT' | 'RATE_LIMITED' | 'INTERNAL_ERROR';

declare class ZiteError extends Error {
  code: ZiteErrorCode;
  /** Create a ZiteError with a code and message */
  constructor(options: { code: ZiteErrorCode; message: string });
}

/** Context type for endpoint execute functions */
type ZiteRequestContext = {
  user: {
    id: string; // The user's unique record ID. IMPORTANT: Use this value when you need to link records to the current user (e.g., for 'createdBy' or 'owner' linked record fields).
    email: string;
    firstName?: string;
    lastName?: string;
    books?: string[] | string;
  };
};

/** Create a typed streaming endpoint (stream is always available when stream: true) */
declare function createEndpoint<TInput, TOutput>(config: {
  /** Optional unique identifier for the endpoint */
  id?: string;
  /** Description of what this endpoint does */
  description?: string;
  /** Whether this endpoint requires authentication (only applies when auth is enabled) */
  authenticated?: boolean;
  /** Enable streaming — the stream parameter will be available in execute */
  stream: true;
  /** Zod schema for input validation */
  inputSchema: TInput;
  /** Zod schema for output validation */
  outputSchema: TOutput;
  /** The endpoint implementation */
  execute: (params: {
    input: InferSchemaType<TInput>;
    context: ZiteRequestContext;
    /** Streaming interface — use stream.forward() or stream.write() to send chunks */
    stream: ZiteStreamInterface;
  }) => Promise<InferSchemaType<TOutput>>;
}): {
  inputSchema: TInput;
  outputSchema: TOutput;
};

/** Create a typed backend endpoint */
declare function createEndpoint<TInput, TOutput>(config: {
  /** Optional unique identifier for the endpoint */
  id?: string;
  /** Description of what this endpoint does */
  description?: string;
  /** Whether this endpoint requires authentication (only applies when auth is enabled) */
  authenticated?: boolean;
  stream?: false;
  /** Zod schema for input validation */
  inputSchema: TInput;
  /** Zod schema for output validation */
  outputSchema: TOutput;
  /** The endpoint implementation */
  execute: (params: {
    input: InferSchemaType<TInput>;
    context: ZiteRequestContext;
  }) => Promise<InferSchemaType<TOutput>>;
}): {
  inputSchema: TInput;
  outputSchema: TOutput;
};

export { ZiteError, createEndpoint };
// ------------------ 
// Zite Database SDK v1.0.0
// Defines the typescript classes/functions to interact with the tables in this base.

// The SDK class and field names are stable identifiers that don't change when renamed. Each table and field has a comment with its current user-facing name in quotes (e.g., // "Task Name").
// Important: The quoted name reflects the most up-to-date name and meaning of the field.
// If the SDK name differs from the quoted name, it means the field was renamed. The quoted name is the source of truth for the meaning of the field.
// Fields may include display configuration in their comments. Values from the database are raw (e.g. ISO strings for dates); your app should format them for display according to these configs.
// LINKED RECORDS: Fields marked "Links to X table" reference records in table X. Values must be UUID record IDs (e.g., "9dceaa44-3f0e-4071-947c-2a9ab6bb4c33") from findOne/findAll - never use fake IDs.
// AI FIELDS: Fields marked "(AI field)" have values automatically generated by AI. They do not compute instantly and may populate after a delay.

/**
 * Some helpful tips when using this SDK:
 * - IMPORTANT: Rate limit is up to 50 requests per second per base.
 * - To avoid hitting rate limits:
 *   - Use bulkCreate() instead of calling create() in a loop
 *   - Use findAll() with filters/pagination instead of calling findOne() repeatedly in a loop
 *   - Keep large data operations paginated and chunked rather than one-record-at-a-time
 *   - If handling many requests, add retry logic for 429 responses
 */

/**
 * Type definition for a record in the "users" table
 */
export type UsersRecordType = {
  email?: string; // Primary field, "Email"
  firstName?: string; // "First Name"
  lastName?: string; // "Last Name"
  books?: string[] | string; // Links to Books table, "books", Single record only
  id: string; // Unique UUID identifier for this record (e.g., "9dceaa44-3f0e-4071-947c-2a9ab6bb4c33"). Use this value when linking records.
};

/**
 * Type definition for a record in the "books" table
 */
export type BooksRecordType = {
