import { z } from 'zod';
import { createEndpoint, Books, ZiteError } from 'zite-integrations-backend-sdk';

const bookInput = z.object({
  id: z.string().optional(),
  bookTitle: z.string(),
  bookType: z.string(),
  grade: z.string(),
  subject: z.string(),
  mapehSubject: z.string().optional(),
  authors: z.string().optional(),
  isbnNumber: z.string().optional(),
  publisher: z.string().optional(),
  copyrightYear: z.number().optional(),
  volume: z.string().optional(),
  schoolName: z.string(),
  district: z.string(),
  distributionDate: z.string(),
  totalUsable: z.number(),
  totalPartiallyDamaged: z.number(),
  totalDamaged: z.number(),
  totalLost: z.number(),
  totalCondemnable: z.number(),
  remarks: z.string().optional(),
});

export default createEndpoint({
  authenticated: true,
  description: 'Create or update a book. Enforces unique title per user. Auto-calculates total.',
  inputSchema: bookInput,
  outputSchema: z.object({ id: z.string() }),
  execute: async ({ input, context }) => {
    const existing = await Books.findAll({
      filters: { user: { contains: context.user.id }, bookTitle: input.bookTitle },
      limit: 5,
    });
    const duplicate = existing.records.find((r) => r.id !== input.id);
    if (duplicate) {
      throw new ZiteError({ code: 'CONFLICT', message: `A book titled "${input.bookTitle}" already exists.` });
    }

    const total = (input.totalUsable ?? 0) + (input.totalPartiallyDamaged ?? 0) +
      (input.totalDamaged ?? 0) + (input.totalLost ?? 0) + (input.totalCondemnable ?? 0);

    const fields = {
      bookTitle: input.bookTitle,
      bookType: input.bookType,
      grade: input.grade,
      subject: input.subject,
      mapehSubject: input.mapehSubject,
      authors: input.authors,
      isbnNumber: input.isbnNumber,
      publisher: input.publisher,
      copyrightYear: input.copyrightYear,
      volume: input.volume,
      schoolName: input.schoolName,
      district: input.district,
      distributionDate: input.distributionDate,
      totalUsable: input.totalUsable,
      totalPartiallyDamaged: input.totalPartiallyDamaged,
      totalDamaged: input.totalDamaged,
      totalLost: input.totalLost,
      totalCondemnable: input.totalCondemnable,
      total,
      remarks: input.remarks,
      user: context.user.id,
    };

    if (input.id) {
      const updated = await Books.update({ id: input.id, record: fields });
      return { id: updated.id };
    }
    const created = await Books.create({ record: fields });
    return { id: created.id };
  },
});

import { z } from 'zod';
import { createEndpoint, Books } from 'zite-integrations-backend-sdk';

const bookRow = z.object({
  bookTitle: z.string(),
  bookType: z.string().optional(),
  grade: z.string().optional(),
  subject: z.string().optional(),
  mapehSubject: z.string().optional(),
  authors: z.string().optional(),
  isbnNumber: z.string().optional(),
  publisher: z.string().optional(),
  copyrightYear: z.number().optional(),
  volume: z.string().optional(),
  schoolName: z.string().optional(),
  district: z.string().optional(),
  distributionDate: z.string().optional(),
  totalUsable: z.number().optional(),
  totalPartiallyDamaged: z.number().optional(),
  totalDamaged: z.number().optional(),
  totalLost: z.number().optional(),
  totalCondemnable: z.number().optional(),
  remarks: z.string().optional(),
});

export default createEndpoint({
  authenticated: true,
  description: 'Bulk import books from CSV, skipping duplicate titles',
  inputSchema: z.object({ books: z.array(bookRow) }),
  outputSchema: z.object({ imported: z.number(), skipped: z.number() }),
  execute: async ({ input, context }) => {
    const existing = await Books.findAll({
      filters: { user: { contains: context.user.id } },
      limit: 2000,
      fields: ['bookTitle'],
    });
    const existingTitles = new Set(existing.records.map((r) => r.bookTitle?.toLowerCase()));
    const unique = input.books.filter((b) => !existingTitles.has(b.bookTitle.toLowerCase()));
    const skipped = input.books.length - unique.length;

    const records = unique.map((b) => ({
      ...b,
      total: (b.totalUsable ?? 0) + (b.totalPartiallyDamaged ?? 0) +
        (b.totalDamaged ?? 0) + (b.totalLost ?? 0) + (b.totalCondemnable ?? 0),
      user: context.user.id,
    }));

    for (let i = 0; i < records.length; i += 100) {
      await Books.bulkCreate({ records: records.slice(i, i + 100) });
    }
    return { imported: records.length, skipped };
  },
});

import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogFooter } from '@/components/ui/dialog';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { BOOK_TYPES, GRADE_LEVELS, SUBJECTS, MAPEH_SUBJECTS, DISTRICTS } from '@/lib/constants';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];
type FormValues = {
  bookTitle: string; bookType: string; grade: string; subject: string; mapehSubject: string;
  authors: string; isbnNumber: string; publisher: string; copyrightYear: string; volume: string;
  schoolName: string; district: string; distributionDate: string;
  totalUsable: number; totalPartiallyDamaged: number; totalDamaged: number;
  totalLost: number; totalCondemnable: number; remarks: string;
};
interface Props {
  open: boolean; onClose: () => void;
  onSave: (data: Omit<Book, 'id'> & { id?: string }) => Promise<void>;
  book?: Book | null; saving?: boolean;
}

function SectionLabel({ children }: { children: React.ReactNode }) {
  return <p className="text-xs font-semibold text-primary uppercase tracking-wide border-b border-border pb-1 mb-3">{children}</p>;
}

export default function BookFormModal({ open, onClose, onSave, book, saving }: Props) {
  const { register, handleSubmit, setValue, watch, reset, formState: { errors } } = useForm<FormValues>();
  const subject = watch('subject');
  const u = Number(watch('totalUsable') || 0), pd = Number(watch('totalPartiallyDamaged') || 0);
  const d = Number(watch('totalDamaged') || 0), l = Number(watch('totalLost') || 0), c = Number(watch('totalCondemnable') || 0);
  const autoTotal = u + pd + d + l + c;

  useEffect(() => {
    if (open) reset({
      bookTitle: book?.bookTitle ?? '', bookType: book?.bookType ?? '', grade: book?.grade ?? '',
      subject: book?.subject ?? '', mapehSubject: book?.mapehSubject ?? '', authors: book?.authors ?? '',
      isbnNumber: book?.isbnNumber ?? '', publisher: book?.publisher ?? '',
      copyrightYear: book?.copyrightYear?.toString() ?? '', volume: book?.volume ?? '',
      schoolName: book?.schoolName ?? '', district: book?.district ?? '',
      distributionDate: book?.distributionDate ?? '',
      totalUsable: book?.totalUsable ?? 0, totalPartiallyDamaged: book?.totalPartiallyDamaged ?? 0,
      totalDamaged: book?.totalDamaged ?? 0, totalLost: book?.totalLost ?? 0,
      totalCondemnable: book?.totalCondemnable ?? 0, remarks: book?.remarks ?? '',
    });
  }, [open, book, reset]);

  const onSubmit = async (data: FormValues) => {
    await onSave({
      ...data,
      copyrightYear: data.copyrightYear ? Number(data.copyrightYear) : undefined,
      totalUsable: Number(data.totalUsable), totalPartiallyDamaged: Number(data.totalPartiallyDamaged),
      totalDamaged: Number(data.totalDamaged), totalLost: Number(data.totalLost),
      totalCondemnable: Number(data.totalCondemnable), total: autoTotal, id: book?.id,
    });
  };

  const sel = (field: keyof FormValues, placeholder: string, options: string[], maxH = '') => (
    <Select value={watch(field) as string} onValueChange={(v) => setValue(field, v)}>
      <SelectTrigger className={errors[field] ? 'border-destructive' : ''}><SelectValue placeholder={placeholder} /></SelectTrigger>
      <SelectContent className={maxH}>{options.map((o) => <SelectItem key={o} value={o}>{o}</SelectItem>)}</SelectContent>
    </Select>
  );

  return (
    <Dialog open={open} onOpenChange={(v) => !v && onClose()}>
      <DialogContent className="max-w-2xl w-full max-h-[90vh] overflow-y-auto">
        <DialogHeader><DialogTitle>{book ? 'Edit Book' : 'Add New Book'}</DialogTitle></DialogHeader>
        <form onSubmit={handleSubmit(onSubmit)} className="space-y-5 py-1">

          <div><SectionLabel>Book Information</SectionLabel>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div className="sm:col-span-2"><Label>Title of the Book *</Label>
                <Input {...register('bookTitle', { required: true })} placeholder="Enter book title" className={errors.bookTitle ? 'border-destructive' : ''} />
              </div>
              <div><Label>Type of Book *</Label>{sel('bookType', 'Select type', BOOK_TYPES)}</div>
              <div><Label>Grade Level *</Label>{sel('grade', 'Select grade level', GRADE_LEVELS)}</div>
              <div><Label>Subject *</Label>{sel('subject', 'Select subject', SUBJECTS)}</div>
              {subject === 'MAPEH' && <div><Label>MAPEH Subject *</Label>{sel('mapehSubject', 'Select MAPEH subject', MAPEH_SUBJECTS)}</div>}
            </div>
          </div>

          <div><SectionLabel>Publication Details</SectionLabel>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div className="sm:col-span-2"><Label>Author/s</Label><Input {...register('authors')} placeholder="e.g. Juan dela Cruz" /></div>
              <div><Label>ISBN Number</Label><Input {...register('isbnNumber')} placeholder="e.g. 978-3-16-148410-0" /></div>
              <div><Label>Publisher</Label><Input {...register('publisher')} placeholder="Publisher name" /></div>
              <div><Label>Copyright Year</Label><Input type="number" {...register('copyrightYear')} placeholder="e.g. 2023" /></div>
              <div><Label>Volume</Label><Input {...register('volume')} placeholder="e.g. Volume 1" /></div>
            </div>
          </div>

          <div><SectionLabel>Delivery Information</SectionLabel>
            <div className="grid grid-cols-1 sm:grid-cols-2 gap-3">
              <div><Label>Name of School Book Delivered *</Label>
                <Input {...register('schoolName', { required: true })} placeholder="School name" className={errors.schoolName ? 'border-destructive' : ''} />
              </div>
              <div><Label>District *</Label>{sel('district', 'Select district', DISTRICTS, 'max-h-56')}</div>
              <div><Label>Date Acquired/Delivered *</Label>
                <Input type="date" {...register('distributionDate', { required: true })} className={errors.distributionDate ? 'border-destructive' : ''} />
              </div>
            </div>
          </div>

          <div><SectionLabel>Book Condition / Inventory Count</SectionLabel>
            <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
              <div><Label>Usable</Label><Input type="number" min={0} {...register('totalUsable')} /></div>
              <div><Label>Partially Damaged</Label><Input type="number" min={0} {...register('totalPartiallyDamaged')} /></div>
              <div><Label>Damaged</Label><Input type="number" min={0} {...register('totalDamaged')} /></div>
              <div><Label>Lost</Label><Input type="number" min={0} {...register('totalLost')} /></div>
              <div><Label>Condemnable</Label><Input type="number" min={0} {...register('totalCondemnable')} /></div>
              <div><Label>TOTAL</Label>
                <div className="flex h-9 items-center rounded-md border border-border bg-muted px-3 text-sm font-bold text-primary">{autoTotal.toLocaleString()}</div>
                <p className="text-xs text-muted-foreground mt-0.5">Auto-calculated</p>
              </div>
            </div>
          </div>

          <div><SectionLabel>Remarks</SectionLabel>
            <Textarea {...register('remarks')} placeholder="Additional notes or remarks..." rows={3} />
          </div>

          <DialogFooter className="gap-2">
            <Button type="button" variant="outline" onClick={onClose} disabled={saving}>Cancel</Button>
            <Button type="submit" disabled={saving}>{saving ? 'Saving...' : book ? 'Update Book' : 'Add Book'}</Button>
          </DialogFooter>
        </form>
      </DialogContent>
    </Dialog>
  );
}

import { useState } from 'react';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Pencil, Trash2, Plus, Search } from 'lucide-react';
import { AlertDialog, AlertDialogAction, AlertDialogCancel, AlertDialogContent, AlertDialogDescription, AlertDialogFooter, AlertDialogHeader, AlertDialogTitle } from '@/components/ui/alert-dialog';
import { Skeleton } from '@/components/ui/skeleton';
import CSVTools from './CSVTools';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];
interface Props {
  books: Book[]; loading: boolean; onAdd: () => void;
  onEdit: (book: Book) => void; onDelete: (id: string) => Promise<void>; onRefresh: () => void;
}

const TH = ({ children }: { children: React.ReactNode }) => (
  <th className="text-left px-3 py-2.5 font-semibold text-muted-foreground whitespace-nowrap text-xs">{children}</th>
);

export default function BookTable({ books, loading, onAdd, onEdit, onDelete, onRefresh }: Props) {
  const [search, setSearch] = useState('');
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [deleting, setDeleting] = useState(false);

  const filtered = books
    .filter((b) => [b.bookTitle, b.bookType, b.subject, b.grade, b.schoolName, b.district, b.authors]
      .some((f) => (f ?? '').toLowerCase().includes(search.toLowerCase())))
    .sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? ''));

  const handleDelete = async () => {
    if (!deleteId) return;
    setDeleting(true);
    await onDelete(deleteId);
    setDeleting(false);
    setDeleteId(null);
  };

  return (
    <div className="space-y-4">
      <div className="flex flex-col sm:flex-row gap-2 items-start sm:items-center justify-between">
        <div className="relative w-full sm:w-72">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-muted-foreground" />
          <Input className="pl-9" placeholder="Search title, type, subject..." value={search} onChange={(e) => setSearch(e.target.value)} />
        </div>
        <div className="flex gap-2 items-center flex-wrap">
          <CSVTools books={books} onImported={onRefresh} />
          <Button size="sm" onClick={onAdd} className="flex items-center gap-1"><Plus className="h-4 w-4" /> Add Book</Button>
        </div>
      </div>

      <div className="text-sm text-muted-foreground">{filtered.length} book{filtered.length !== 1 ? 's' : ''} found</div>

      {loading ? (
        <div className="space-y-2">{Array.from({ length: 5 }).map((_, i) => <Skeleton key={i} className="h-14 w-full rounded-lg" />)}</div>
      ) : filtered.length === 0 ? (
        <div className="text-center py-16 text-muted-foreground">
          <p className="text-lg font-medium">No books found</p>
          <p className="text-sm mt-1">{search ? 'Try a different search term' : 'Add your first book to get started'}</p>
        </div>
      ) : (
        <div className="overflow-x-auto rounded-lg border border-border">
          <table className="w-full text-sm">
            <thead className="bg-muted">
              <tr><TH>Title</TH><TH>Type</TH><TH>Grade Level</TH><TH>Subject</TH><TH>School</TH><TH>District</TH><TH>Date</TH><TH>Usable</TH><TH>Total</TH><TH>Remarks</TH><th className="px-3 py-2.5"></th></tr>
            </thead>
            <tbody className="divide-y divide-border">
              {filtered.map((book) => (
                <tr key={book.id} className="hover:bg-muted/40 transition-colors">
                  <td className="px-3 py-2.5 font-medium max-w-[160px] truncate text-foreground">{book.bookTitle}</td>
                  <td className="px-3 py-2.5 max-w-[110px] truncate text-foreground">{book.bookType ?? '—'}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap text-foreground">{book.grade ?? '—'}</td>
                  <td className="px-3 py-2.5 max-w-[130px] truncate text-foreground">{book.subject === 'MAPEH' && book.mapehSubject ? `MAPEH – ${book.mapehSubject}` : (book.subject ?? '—')}</td>
                  <td className="px-3 py-2.5 max-w-[130px] truncate text-foreground">{book.schoolName ?? '—'}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap text-foreground">{book.district ?? '—'}</td>
                  <td className="px-3 py-2.5 whitespace-nowrap text-foreground">{book.distributionDate ? new Date(book.distributionDate).toLocaleDateString() : '—'}</td>
                  <td className="px-3 py-2.5 text-center font-semibold text-green-700">{book.totalUsable?.toLocaleString() ?? '—'}</td>
                  <td className="px-3 py-2.5 text-center font-bold text-primary">{book.total?.toLocaleString() ?? '—'}</td>
                  <td className="px-3 py-2.5 max-w-[120px] truncate text-muted-foreground text-xs">{book.remarks ?? '—'}</td>
                  <td className="px-3 py-2.5">
                    <div className="flex gap-1 justify-end">
                      <Button variant="ghost" size="icon" className="h-7 w-7" onClick={() => onEdit(book)}><Pencil className="h-3.5 w-3.5" /></Button>
                      <Button variant="ghost" size="icon" className="h-7 w-7 text-destructive hover:text-destructive" onClick={() => setDeleteId(book.id)}><Trash2 className="h-3.5 w-3.5" /></Button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      <AlertDialog open={!!deleteId} onOpenChange={(v) => !v && setDeleteId(null)}>
        <AlertDialogContent>
          <AlertDialogHeader><AlertDialogTitle>Delete Book</AlertDialogTitle>
            <AlertDialogDescription>Are you sure you want to delete this book? This cannot be undone.</AlertDialogDescription>
          </AlertDialogHeader>
          <AlertDialogFooter>
            <AlertDialogCancel disabled={deleting}>Cancel</AlertDialogCancel>
            <AlertDialogAction onClick={handleDelete} disabled={deleting} className="bg-destructive hover:bg-destructive/90">
              {deleting ? 'Deleting...' : 'Delete'}
            </AlertDialogAction>
          </AlertDialogFooter>
        </AlertDialogContent>
      </AlertDialog>
    </div>
  );
}

import { useState, useEffect, useCallback } from 'react';
import { getBooks, saveBook, deleteBook } from 'zite-endpoints-sdk';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';
import BookTable from '@/components/BookTable';
import BookFormModal from '@/components/BookFormModal';
import { Toaster } from '@/components/ui/sonner';
import { toast } from 'sonner';

type Book = GetBooksOutputType['books'][0];

export default function InventoryPage() {
  const [books, setBooks] = useState<Book[]>([]);
  const [loading, setLoading] = useState(true);
  const [modalOpen, setModalOpen] = useState(false);
  const [editBook, setEditBook] = useState<Book | null>(null);
  const [saving, setSaving] = useState(false);

  const fetchBooks = useCallback(async () => {
    setLoading(true);
    try { const result = await getBooks({}); setBooks(result.books); }
    catch { toast.error('Failed to load books'); }
    finally { setLoading(false); }
  }, []);

  useEffect(() => { fetchBooks(); }, [fetchBooks]);

  const handleSave = async (data: Omit<Book, 'id'> & { id?: string }) => {
    setSaving(true);
    try {
      await saveBook({
        bookTitle: data.bookTitle ?? '',
        bookType: data.bookType ?? '',
        grade: data.grade ?? '',
        subject: data.subject ?? '',
        mapehSubject: data.mapehSubject,
        authors: data.authors,
        isbnNumber: data.isbnNumber,
        publisher: data.publisher,
        copyrightYear: data.copyrightYear,
        volume: data.volume,
        schoolName: data.schoolName ?? '',
        district: data.district ?? '',
        distributionDate: data.distributionDate ?? '',
        totalUsable: data.totalUsable ?? 0,
        totalPartiallyDamaged: data.totalPartiallyDamaged ?? 0,
        totalDamaged: data.totalDamaged ?? 0,
        totalLost: data.totalLost ?? 0,
        totalCondemnable: data.totalCondemnable ?? 0,
        remarks: data.remarks,
        id: data.id,
      });
      toast.success(data.id ? 'Book updated!' : 'Book added!');
      setModalOpen(false);
      setEditBook(null);
      fetchBooks();
    } catch (e: any) {
      toast.error(e?.message ?? 'Failed to save book');
    } finally { setSaving(false); }
  };

  const handleDelete = async (id: string) => {
    await deleteBook({ id });
    toast.success('Book deleted');
    fetchBooks();
  };

  return (
    <div className="space-y-0">
      <Toaster />
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-foreground">Book Inventory</h1>
        <p className="text-muted-foreground text-sm mt-1">Manage your learning resource distribution records</p>
      </div>
      <BookTable
        books={books} loading={loading}
        onAdd={() => { setEditBook(null); setModalOpen(true); }}
        onEdit={(book) => { setEditBook(book); setModalOpen(true); }}
        onDelete={handleDelete} onRefresh={fetchBooks}
      />
      <BookFormModal
        open={modalOpen}
        onClose={() => { setModalOpen(false); setEditBook(null); }}
        onSave={handleSave} book={editBook} saving={saving}
      />
    </div>
  );
}

import { useRef } from 'react';
import { Button } from '@/components/ui/button';
import { Upload, Download } from 'lucide-react';
import { importBooks } from 'zite-endpoints-sdk';
import { toast } from 'sonner';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];
interface Props { books: Book[]; onImported: () => void; }

const HEADERS = ['Title','Book Type','Grade Level','Subject','MAPEH Subject','Author/s','ISBN Number','Publisher','Copyright Year','Volume','School Name','District','Date Acquired/Delivered','Total Usable','Total Partially Damaged','Total Damaged','Total Lost','Total Condemnable','Total','Remarks'];

export default function CSVTools({ books, onImported }: Props) {
  const fileRef = useRef<HTMLInputElement>(null);

  const handleExport = () => {
    const rows = books.map((b) => [
      `"${(b.bookTitle ?? '').replace(/"/g, '""')}"`, b.bookType ?? '', b.grade ?? '',
      b.subject ?? '', b.mapehSubject ?? '', `"${(b.authors ?? '').replace(/"/g, '""')}"`,
      b.isbnNumber ?? '', `"${(b.publisher ?? '').replace(/"/g, '""')}"`,
      b.copyrightYear ?? '', b.volume ?? '', `"${(b.schoolName ?? '').replace(/"/g, '""')}"`,
      b.district ?? '', b.distributionDate ?? '', b.totalUsable ?? 0,
      b.totalPartiallyDamaged ?? 0, b.totalDamaged ?? 0, b.totalLost ?? 0,
      b.totalCondemnable ?? 0, b.total ?? 0, `"${(b.remarks ?? '').replace(/"/g, '""')}"`,
    ]);
    const csv = [HEADERS.join(','), ...rows.map((r) => r.join(','))].join('\n');
    const url = URL.createObjectURL(new Blob([csv], { type: 'text/csv' }));
    const a = document.createElement('a');
    a.href = url; a.download = `inventory-${new Date().toISOString().split('T')[0]}.csv`; a.click();
    URL.revokeObjectURL(url);
    toast.success(`Exported ${books.length} books`);
  };

  const handleImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    const lines = (await file.text()).split('\n').filter((l) => l.trim());
    if (lines.length < 2) { toast.error('CSV is empty or invalid'); return; }
    const parsed = lines.slice(1).map((line) => {
      const c = line.split(',').map((x) => x.trim().replace(/^"|"$/g, '').replace(/""/g, '"'));
      return {
        bookTitle: c[0] ?? '', bookType: c[1], grade: c[2], subject: c[3], mapehSubject: c[4],
        authors: c[5], isbnNumber: c[6], publisher: c[7],
        copyrightYear: c[8] ? Number(c[8]) : undefined, volume: c[9],
        schoolName: c[10], district: c[11], distributionDate: c[12],
        totalUsable: Number(c[13]) || 0, totalPartiallyDamaged: Number(c[14]) || 0,
        totalDamaged: Number(c[15]) || 0, totalLost: Number(c[16]) || 0,
        totalCondemnable: Number(c[17]) || 0, remarks: c[19],
      };
    }).filter((b) => b.bookTitle);
    if (!parsed.length) { toast.error('No valid rows found'); return; }
    try {
      const r = await importBooks({ books: parsed });
      toast.success(`Imported ${r.imported} books${r.skipped > 0 ? ` (${r.skipped} skipped – duplicates)` : ''}`);
      onImported();
    } catch { toast.error('Import failed. Check your CSV format.'); }
    e.target.value = '';
  };

  return (
    <div className="flex gap-2">
      <input ref={fileRef} type="file" accept=".csv" className="hidden" onChange={handleImport} />
      <Button variant="outline" size="sm" onClick={() => fileRef.current?.click()} className="flex items-center gap-1">
        <Upload className="h-4 w-4" /><span className="hidden sm:inline">Import CSV</span>
      </Button>
      <Button variant="outline" size="sm" onClick={handleExport} className="flex items-center gap-1">
        <Download className="h-4 w-4" /><span className="hidden sm:inline">Export CSV</span>
      </Button>
    </div>
  );
}

import { useState, useMemo } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from '@/components/ui/select';
import { Label } from '@/components/ui/label';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, CartesianGrid } from 'recharts';
import { SUBJECTS, DISTRICTS, DATE_RANGE_OPTIONS, GRADE_LEVELS } from '@/lib/constants';
import type { GetBooksOutputType } from 'zite-endpoints-sdk';

type Book = GetBooksOutputType['books'][0];
interface Props { books: Book[] }

function getDateCutoff(range: string): Date | null {
  const now = new Date();
  if (range === '7days') return new Date(now.setDate(now.getDate() - 7));
  if (range === 'month') return new Date(now.setMonth(now.getMonth() - 1));
  if (range === 'quarter') return new Date(now.setMonth(now.getMonth() - 3));
  if (range === 'year') return new Date(now.setFullYear(now.getFullYear() - 1));
  return null;
}

export default function ReportsView({ books }: Props) {
  const [dateRange, setDateRange] = useState('all');
  const [district, setDistrict] = useState('all');
  const [subject, setSubject] = useState('all');
  const [gradeLevel, setGradeLevel] = useState('all');

  const filtered = useMemo(() => {
    const cutoff = getDateCutoff(dateRange);
    return books.filter((b) => {
      if (cutoff && b.distributionDate && new Date(b.distributionDate) < cutoff) return false;
      if (district !== 'all' && b.district !== district) return false;
      if (subject !== 'all' && b.subject !== subject) return false;
      if (gradeLevel !== 'all' && b.grade !== gradeLevel) return false;
      return true;
    });
  }, [books, dateRange, district, subject, gradeLevel]);

  const totalBooks = filtered.length;
  const totalUsable = filtered.reduce((s, b) => s + (b.totalUsable ?? 0), 0);
  const grandTotal = filtered.reduce((s, b) => s + (b.total ?? 0), 0);

  const bySubject = useMemo(() => SUBJECTS.map((s) => ({
    name: s.length > 14 ? s.slice(0, 14) + '…' : s, fullName: s,
    total: filtered.filter((b) => b.subject === s).reduce((a, b) => a + (b.total ?? 0), 0),
  })).filter((x) => x.total > 0), [filtered]);

  const byDistrict = useMemo(() => {
    const map: Record<string, number> = {};
    filtered.forEach((b) => { if (b.district) map[b.district] = (map[b.district] ?? 0) + (b.total ?? 0); });
    return Object.entries(map).map(([name, total]) => ({ name, total })).sort((a, b) => b.total - a.total).slice(0, 15);
  }, [filtered]);

  return (
    <div className="space-y-6">
      <Card>
        <CardHeader><CardTitle className="text-base">Filters</CardTitle></CardHeader>
        <CardContent>
          <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
            <div><Label className="mb-1 block">Date Range</Label>
              <Select value={dateRange} onValueChange={setDateRange}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent>{DATE_RANGE_OPTIONS.map((o) => <SelectItem key={o.value} value={o.value}>{o.label}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">Grade Level</Label>
              <Select value={gradeLevel} onValueChange={setGradeLevel}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent><SelectItem value="all">All Levels</SelectItem>{GRADE_LEVELS.map((g) => <SelectItem key={g} value={g}>{g}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">Subject</Label>
              <Select value={subject} onValueChange={setSubject}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent><SelectItem value="all">All Subjects</SelectItem>{SUBJECTS.map((s) => <SelectItem key={s} value={s}>{s}</SelectItem>)}</SelectContent>
              </Select>
            </div>
            <div><Label className="mb-1 block">District</Label>
              <Select value={district} onValueChange={setDistrict}>
                <SelectTrigger><SelectValue /></SelectTrigger>
                <SelectContent className="max-h-56"><SelectItem value="all">All Districts</SelectItem>{DISTRICTS.map((d) => <SelectItem key={d} value={d}>{d}</SelectItem>)}</SelectContent>
              </Select>
            </div>
          </div>
        </CardContent>
      </Card>

      <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
        <Card><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-primary">{totalBooks}</p><p className="text-sm text-muted-foreground mt-1">Total Books</p></CardContent></Card>
        <Card><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-green-700">{totalUsable.toLocaleString()}</p><p className="text-sm text-muted-foreground mt-1">Usable Copies</p></CardContent></Card>
        <Card className="col-span-2 sm:col-span-1"><CardContent className="pt-5 text-center"><p className="text-3xl font-bold text-primary">{grandTotal.toLocaleString()}</p><p className="text-sm text-muted-foreground mt-1">Grand Total</p></CardContent></Card>
      </div>

      {bySubject.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Books by Subject</CardTitle></CardHeader>
          <CardContent>
            <ResponsiveContainer width="100%" height={220}>
              <BarChart data={bySubject} margin={{ top: 5, right: 10, left: 0, bottom: 5 }}>
                <CartesianGrid strokeDasharray="3 3" className="stroke-border" />
                <XAxis dataKey="name" tick={{ fontSize: 11 }} />
                <YAxis tick={{ fontSize: 11 }} />
                <Tooltip formatter={(v, _, p) => [v, p.payload.fullName]} />
                <Bar dataKey="total" className="fill-primary" radius={[4, 4, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </CardContent>
        </Card>
      )}

      {byDistrict.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Top Districts by Total Books</CardTitle></CardHeader>
          <CardContent>
            <div className="space-y-2">
              {byDistrict.map((d) => (
                <div key={d.name} className="flex items-center gap-3">
                  <span className="w-24 text-sm text-muted-foreground shrink-0">{d.name}</span>
                  <div className="flex-1 bg-muted rounded-full h-5 overflow-hidden">
                    <div className="bg-primary h-full rounded-full transition-all" style={{ width: `${(d.total / (byDistrict[0]?.total || 1)) * 100}%` }} />
                  </div>
                  <span className="text-sm font-semibold w-16 text-right">{d.total.toLocaleString()}</span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      )}

      {filtered.length > 0 && (
        <Card>
          <CardHeader><CardTitle className="text-base">Distribution Details ({filtered.length} records)</CardTitle></CardHeader>
          <CardContent>
            <div className="overflow-x-auto">
              <table className="w-full text-sm">
                <thead className="bg-muted">
                  <tr>{['Title','Type','Grade','Subject','School','District','Date','Usable','Partial','Damaged','Lost','Condemnable','Total','Remarks'].map((h) => (
                    <th key={h} className="text-left px-3 py-2 font-semibold text-muted-foreground whitespace-nowrap text-xs">{h}</th>
                  ))}</tr>
                </thead>
                <tbody className="divide-y divide-border">
                  {[...filtered].sort((a, b) => (a.bookTitle ?? '').localeCompare(b.bookTitle ?? '')).map((b) => (
                    <tr key={b.id} className="hover:bg-muted/40">
                      <td className="px-3 py-2 font-medium max-w-[130px] truncate">{b.bookTitle}</td>
                      <td className="px-3 py-2 max-w-[90px] truncate text-muted-foreground">{b.bookType}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.grade}</td>
                      <td className="px-3 py-2 max-w-[110px] truncate">{b.subject === 'MAPEH' && b.mapehSubject ? `MAPEH–${b.mapehSubject}` : b.subject}</td>
                      <td className="px-3 py-2 max-w-[110px] truncate text-muted-foreground">{b.schoolName}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.district}</td>
                      <td className="px-3 py-2 whitespace-nowrap text-muted-foreground">{b.distributionDate ? new Date(b.distributionDate).toLocaleDateString() : '—'}</td>
                      <td className="px-3 py-2 text-right text-green-700 font-semibold">{b.totalUsable ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalPartiallyDamaged ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalDamaged ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalLost ?? 0}</td>
                      <td className="px-3 py-2 text-right">{b.totalCondemnable ?? 0}</td>
                      <td className="px-3 py-2 text-right font-bold text-primary">{b.total ?? 0}</td>
                      <td className="px-3 py-2 max-w-[100px] truncate text-muted-foreground text-xs">{b.remarks ?? '—'}</td>
                    </tr>
                  ))}
                </tbody>
                <tfoot className="bg-muted font-semibold">
                  <tr>
                    <td colSpan={7} className="px-3 py-2 text-right text-sm">Totals:</td>
                    <td className="px-3 py-2 text-right text-green-700">{filtered.reduce((s, b) => s + (b.totalUsable ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalPartiallyDamaged ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalDamaged ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalLost ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right">{filtered.reduce((s, b) => s + (b.totalCondemnable ?? 0), 0)}</td>
                    <td className="px-3 py-2 text-right text-primary">{grandTotal.toLocaleString()}</td>
                    <td></td>
                  </tr>
                </tfoot>
              </table>
            </div>
          </CardContent>
        </Card>
      )}
      {filtered.length === 0 && <div className="text-center py-12 text-muted-foreground"><p className="text-lg font-medium">No data for selected filters</p></div>}
    </div>
  );
}

